 * @param {React.ReactNode}   props.sliver   — sliver child (alias for children)
 */
export function SliverPadding({ padding, sliver, children }) {
  const p = resolveInsets(padding);
  return (
    <div style={{
      paddingTop:    p.top,
      paddingRight:  p.right,
      paddingBottom: p.bottom,
      paddingLeft:   p.left,
      flexShrink: 0,
