import React, { useState, useEffect, useRef, CSSProperties } from "react";
import { cn } from "../utils";

// ─── Types ────────────────────────────────────────────────────────────────────
interface AnimatedValue {
  width?: number | string;
  height?: number | string;
  color?: string;
  padding?: number | string;
  margin?: number | string;
  borderRadius?: number | string;
  opacity?: number;
  transform?: string;
}

interface AnimatedContainerProps {
  duration?: number; // ms
  curve?: "ease" | "easeIn" | "easeOut" | "easeInOut" | "linear" | "spring";
  width?: number | string;
  height?: number | string;
  color?: string;
  padding?: number | string;
  margin?: number | string;
  borderRadius?: number | string;
  opacity?: number;
  transform?: string;
  child?: React.ReactNode;
  children?: React.ReactNode;
  onEnd?: () => void;
  className?: string;
}

const CURVE_MAP: Record<string, string> = {
  ease: "ease",
  easeIn: "ease-in",
  easeOut: "ease-out",
  easeInOut: "ease-in-out",
  linear: "linear",
  spring: "cubic-bezier(0.34, 1.56, 0.64, 1)",
};

// ─── AnimatedContainer ────────────────────────────────────────────────────────
export function AnimatedContainer({
  duration = 300,
  curve = "easeInOut",
  width,
  height,
  color,
  padding,
  margin,
  borderRadius,
  opacity,
  transform,
  children,
  child,
  onEnd,
  className,
}: AnimatedContainerProps) {
  const style: CSSProperties = {
    transition: `all ${duration}ms ${CURVE_MAP[curve] || "ease-in-out"}`,
    width: width,
    height: height,
    backgroundColor: color,
    padding: padding,
    margin: margin,
    borderRadius: borderRadius,
    opacity: opacity,
    transform: transform,
  };

  return (
    <div
      className={cn("overflow-hidden", className)}
      style={style}
      onTransitionEnd={onEnd}
    >
      {children ?? child}
    </div>
  );
}

// ─── AnimatedOpacity ──────────────────────────────────────────────────────────
interface AnimatedOpacityProps {
  opacity: number;
  duration?: number;
  curve?: string;
  children: React.ReactNode;
  className?: string;
  onEnd?: () => void;
}

export function AnimatedOpacity({
  opacity,
  duration = 300,
  curve = "easeInOut",
  children,
  className,
  onEnd,
}: AnimatedOpacityProps) {
  return (
    <div
      className={className}
      style={{
        opacity,
        transition: `opacity ${duration}ms ${CURVE_MAP[curve] || "ease-in-out"}`,
      }}
      onTransitionEnd={onEnd}
    >
      {children}
    </div>
  );
}

// ─── AnimatedScale ────────────────────────────────────────────────────────────
interface AnimatedScaleProps {
  scale: number;
  duration?: number;
  curve?: string;
  children: React.ReactNode;
  className?: string;
}

export function AnimatedScale({
  scale,
  duration = 300,
  curve = "easeInOut",
  children,
  className,
}: AnimatedScaleProps) {
  return (
    <div
      className={cn("inline-block", className)}
      style={{
        transform: `scale(${scale})`,
        transition: `transform ${duration}ms ${CURVE_MAP[curve] || "ease-in-out"}`,
      }}
    >
      {children}
    </div>
  );
}

// ─── AnimatedSlide ────────────────────────────────────────────────────────────
interface AnimatedSlideProps {
  offset: { x: number; y: number };
  duration?: number;
  curve?: string;
  children: React.ReactNode;
  className?: string;
}

export function AnimatedSlide({
  offset,
  duration = 300,
  curve = "easeInOut",
  children,
  className,
}: AnimatedSlideProps) {
  return (
    <div
      className={className}
      style={{
        transform: `translate(${offset.x * 100}%, ${offset.y * 100}%)`,
