}

interface BottomNavigationBarProps {
  items: BottomNavItem[];
  currentIndex: number;
  onTap: (index: number) => void;
  type?: "fixed" | "shifting";
  selectedItemColor?: string;
  unselectedItemColor?: string;
  backgroundColor?: string;
