// ─── BottomNavigationBar ──────────────────────────────────────────────────────
export function BottomNavigationBar({
  items,
  currentIndex,
  onTap,
  type = "fixed",
  selectedItemColor,
  unselectedItemColor,
  backgroundColor,
  elevation = 8,
  showSelectedLabels = true,
  showUnselectedLabels = true,
  className,
}: BottomNavigationBarProps) {
  const shadowMap: Record<number, string> = {
    0: "shadow-none",
    2: "shadow-sm",
    4: "shadow-md",
    8: "shadow-xl",
    16: "shadow-2xl",
  };

  return (
    <nav
      className={cn(
        "flex items-stretch border-t border-border",
        shadowMap[elevation] || "shadow-xl",
        className
      )}
      style={{ backgroundColor: backgroundColor || "hsl(var(--card))" }}
    >
      {items.map((item, i) => {
        const isSelected = i === currentIndex;
        return (
          <button
            key={i}
            onClick={() => onTap(i)}
            className={cn(
              "flex-1 flex flex-col items-center justify-center gap-1 py-2 px-1 relative transition-all",
              "hover:bg-accent/30"
            )}
            style={{
