        onKeyDown={isInteractive ? (e) => { if (e.key === "Enter" || e.key === " ") onTap!(); } : undefined}
        onMouseEnter={() => setIsHovered(true)}
        onMouseLeave={() => setIsHovered(false)}
        className={cn(
          "overflow-hidden",
