import { cn } from "../utils";

// ─── Types ────────────────────────────────────────────────────────────────────
export interface DataColumn<T = Record<string, unknown>> {
  id: string;
  label: React.ReactNode;
  numeric?: boolean;
  sortable?: boolean;
  minWidth?: number;
  accessor: (row: T) => React.ReactNode;
}

interface DataTableProps<T = Record<string, unknown>> {
  columns: DataColumn<T>[];
  rows: T[];
  onRowTap?: (row: T, index: number) => void;
  sortAscending?: boolean;
  sortColumnIndex?: number;
  onSort?: (columnIndex: number, ascending: boolean) => void;
  showCheckboxColumn?: boolean;
  selectedRows?: number[];
  onSelectRow?: (index: number, selected: boolean) => void;
  onSelectAll?: (selected: boolean) => void;
  headingRowColor?: string;
  dataRowColor?: string;
  dividerThickness?: number;
  className?: string;
}

// ─── DataTable ────────────────────────────────────────────────────────────────
export function DataTable<T = Record<string, unknown>>({
  columns,
  rows,
  onRowTap,
  sortAscending = true,
  sortColumnIndex,
  onSort,
  showCheckboxColumn = false,
  selectedRows = [],
  onSelectRow,
  onSelectAll,
  headingRowColor,
  dataRowColor,
  dividerThickness = 1,
  className,
}: DataTableProps<T>) {
  const allSelected = selectedRows.length === rows.length && rows.length > 0;
  const someSelected = selectedRows.length > 0 && !allSelected;

  return (
    <div className={cn("w-full overflow-x-auto rounded-xl border border-border", className)}>
      <table className="w-full text-xs border-collapse">
        {/* Header */}
        <thead>
          <tr
            style={{
              backgroundColor: headingRowColor || undefined,
              borderBottom: `${dividerThickness}px solid hsl(var(--border))`,
            }}
            className={!headingRowColor ? "bg-muted/50" : ""}
          >
            {showCheckboxColumn && (
              <th className="px-3 py-3 w-8">
                <input
                  type="checkbox"
                  checked={allSelected}
                  ref={(el) => { if (el) el.indeterminate = someSelected; }}
                  onChange={(e) => onSelectAll?.(e.target.checked)}
                  className="cursor-pointer accent-primary"
                />
              </th>
            )}
            {columns.map((col, i) => (
              <th
                key={col.id}
                className={cn(
                  "px-4 py-3 font-semibold tracking-wide text-muted-foreground text-left",
                  col.numeric ? "text-right" : "",
                  col.sortable ? "cursor-pointer select-none hover:text-foreground transition-colors" : ""
                )}
                style={{ minWidth: col.minWidth }}
                onClick={col.sortable ? () => onSort?.(i, sortColumnIndex === i ? !sortAscending : true) : undefined}
              >
                <span className="flex items-center gap-1">
                  {col.label}
                  {col.sortable && sortColumnIndex === i && (
                    <span className="text-primary">{sortAscending ? "↑" : "↓"}</span>
                  )}
                </span>
              </th>
            ))}
          </tr>
        </thead>

        {/* Body */}
        <tbody>
          {rows.map((row, rowIdx) => {
            const isSelected = selectedRows.includes(rowIdx);
            return (
              <tr
                key={rowIdx}
                onClick={() => onRowTap?.(row, rowIdx)}
                className={cn(
                  "transition-colors",
                  onRowTap ? "cursor-pointer hover:bg-accent/40" : "",
                  isSelected ? "bg-primary/10" : ""
                )}
                style={{
                  backgroundColor: !isSelected && dataRowColor ? dataRowColor : undefined,
                  borderBottom: `${dividerThickness}px solid hsl(var(--border))`,
                }}
              >
                {showCheckboxColumn && (
                  <td className="px-3 py-2.5" onClick={(e) => e.stopPropagation()}>
                    <input
                      type="checkbox"
                      checked={isSelected}
                      onChange={(e) => onSelectRow?.(rowIdx, e.target.checked)}
                      className="cursor-pointer accent-primary"
                    />
                  </td>
                )}
                {columns.map((col) => (
                  <td
                    key={col.id}
                    className={cn("px-4 py-2.5 text-foreground/90", col.numeric ? "text-right" : "")}
                  >
                    {col.accessor(row)}
                  </td>
                ))}
              </tr>
            );
          })}
          {rows.length === 0 && (
            <tr>
              <td
                colSpan={columns.length + (showCheckboxColumn ? 1 : 0)}
                className="text-center py-10 text-muted-foreground"
              >
                No data available
              </td>
            </tr>
          )}
        </tbody>
      </table>
    </div>
  );
}

import React, { useState } from "react";
import { cn } from "../utils";

// ─── Types ────────────────────────────────────────────────────────────────────
interface DatePickerProps {
  isOpen: boolean;
  onClose: () => void;
  onDateSelected: (date: Date) => void;
  initialDate?: Date;
  firstDate?: Date;
  lastDate?: Date;
  className?: string;
}

// ─── Helper ───────────────────────────────────────────────────────────────────
const MONTHS = [
  "January","February","March","April","May","June",
  "July","August","September","October","November","December"
];
const DAYS = ["Sun","Mon","Tue","Wed","Thu","Fri","Sat"];

function getDaysInMonth(year: number, month: number) {
  return new Date(year, month + 1, 0).getDate();
}

function getFirstDayOfMonth(year: number, month: number) {
  return new Date(year, month, 1).getDay();
}

// ─── DatePicker ───────────────────────────────────────────────────────────────
export function DatePicker({
  isOpen,
  onClose,
  onDateSelected,
  initialDate = new Date(),
  firstDate,
  lastDate,
  className,
}: DatePickerProps) {
  const [viewDate, setViewDate] = useState(initialDate);
  const [selected, setSelected] = useState<Date | null>(null);

  if (!isOpen) return null;

  const year = viewDate.getFullYear();
  const month = viewDate.getMonth();
  const daysInMonth = getDaysInMonth(year, month);
  const firstDay = getFirstDayOfMonth(year, month);

  const prevMonth = () => setViewDate(new Date(year, month - 1, 1));
  const nextMonth = () => setViewDate(new Date(year, month + 1, 1));

  const selectDay = (day: number) => {
    const d = new Date(year, month, day);
    setSelected(d);
    onDateSelected(d);
    onClose();
  };

  const isDisabled = (day: number) => {
    const d = new Date(year, month, day);
    if (firstDate && d < firstDate) return true;
    if (lastDate && d > lastDate) return true;
    return false;
  };

  const isToday = (day: number) => {
    const today = new Date();
    return today.getFullYear() === year && today.getMonth() === month && today.getDate() === day;
  };

  const cells = [];
  // Empty cells before first day
  for (let i = 0; i < firstDay; i++) cells.push(null);
  // Day cells
  for (let d = 1; d <= daysInMonth; d++) cells.push(d);

  return (
    <div className="fixed inset-0 z-50 flex items-center justify-center bg-black/50 backdrop-blur-sm">
      <div className={cn("bg-card border border-border rounded-2xl shadow-2xl w-72 overflow-hidden", className)}>
        {/* Header */}
        <div className="flex items-center justify-between px-5 py-4 bg-primary text-primary-foreground">
          <button onClick={prevMonth} className="p-1 rounded-full hover:bg-white/20 transition">
            <svg width="16" height="16" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth={2.5}>
              <path d="M15 18l-6-6 6-6" strokeLinecap="round" />
            </svg>
          </button>
          <span className="font-bold text-sm">
            {MONTHS[month]} {year}
          </span>
          <button onClick={nextMonth} className="p-1 rounded-full hover:bg-white/20 transition">
            <svg width="16" height="16" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth={2.5}>
              <path d="M9 18l6-6-6-6" strokeLinecap="round" />
            </svg>
          </button>
        </div>

        {/* Day names */}
        <div className="grid grid-cols-7 px-3 pt-3 pb-1">
          {DAYS.map((d) => (
            <div key={d} className="text-center text-[10px] font-bold text-muted-foreground">
              {d}
            </div>
          ))}
        </div>

        {/* Day grid */}
        <div className="grid grid-cols-7 gap-0.5 px-3 pb-4">
          {cells.map((day, i) =>
            day === null ? (
              <div key={`empty-${i}`} />
            ) : (
              <button
                key={day}
                onClick={() => !isDisabled(day) && selectDay(day)}
                disabled={isDisabled(day)}
                className={cn(
                  "aspect-square flex items-center justify-center rounded-full text-xs font-medium transition-all",
                  isDisabled(day)
                    ? "text-muted-foreground/30 cursor-not-allowed"
                    : isToday(day)
                    ? "bg-primary/20 text-primary font-bold hover:bg-primary hover:text-primary-foreground"
                    : "hover:bg-accent text-foreground"
                )}
              >
                {day}
              </button>
            )
          )}
        </div>

        {/* Actions */}
        <div className="flex justify-end gap-2 px-4 py-3 border-t border-border">
          <button
            onClick={onClose}
            className="px-3 py-1.5 text-xs font-semibold text-muted-foreground hover:text-foreground transition"
          >
            CANCEL
          </button>
        </div>
      </div>
    </div>
  );
}

// ─── showDatePicker helper (returns selected date via callback) ────────────────
export function showDatePicker({
  context: _context,
  initialDate,
  firstDate,
  lastDate,
  onSelected,
}: {
  context?: unknown;
  initialDate?: Date;
  firstDate?: Date;
  lastDate?: Date;
  onSelected: (date: Date) => void;
}) {
  // In React, render the <DatePicker> component directly with state
  console.warn("showDatePicker: Render <DatePicker> component with isOpen state instead.");
  return null;
}

