// ─── Types ────────────────────────────────────────────────────────────────────
interface ExpansionTileProps {
  title: React.ReactNode;
  subtitle?: React.ReactNode;
  leading?: React.ReactNode;
  trailing?: React.ReactNode;
  children: React.ReactNode;
  initiallyExpanded?: boolean;
  onExpansionChanged?: (expanded: boolean) => void;
  expandedCrossAxisAlignment?: "start" | "center" | "end" | "stretch";
  tilePadding?: string;
  childrenPadding?: string;
  backgroundColor?: string;
  collapsedBackgroundColor?: string;
  iconColor?: string;
  collapsedIconColor?: string;
  textColor?: string;
  collapsedTextColor?: string;
  className?: string;
  maintainState?: boolean;
}

// ─── ExpansionTile ────────────────────────────────────────────────────────────
export function ExpansionTile({
  title,
  subtitle,
  leading,
  trailing,
  children,
  initiallyExpanded = false,
  onExpansionChanged,
  tilePadding = "px-4 py-3",
  childrenPadding = "px-4 pb-4",
  backgroundColor,
  collapsedBackgroundColor,
  iconColor,
  collapsedIconColor,
  textColor,
  collapsedTextColor,
  className,
  maintainState = false,
}: ExpansionTileProps) {
  const [isExpanded, setIsExpanded] = useState(initiallyExpanded);

  const toggle = () => {
    const next = !isExpanded;
    setIsExpanded(next);
    onExpansionChanged?.(next);
  };

  return (
    <div
      className={cn(
        "border border-border rounded-xl overflow-hidden transition-colors",
        className
      )}
      style={{
        backgroundColor: isExpanded
          ? backgroundColor
          : collapsedBackgroundColor || undefined,
      }}
    >
      {/* Tile Header */}
      <button
        onClick={toggle}
        className={cn(
          "w-full flex items-center gap-3 text-left transition-colors hover:bg-accent/30",
          tilePadding
        )}
        style={{ color: isExpanded ? textColor : collapsedTextColor || undefined }}
      >
        {leading && <span className="shrink-0">{leading}</span>}

        <div className="flex-1 min-w-0">
          <div className="text-sm font-semibold truncate">{title}</div>
          {subtitle && (
            <div className="text-xs text-muted-foreground truncate mt-0.5">{subtitle}</div>
          )}
        </div>

        {trailing || (
          <span
            className={cn(
              "transition-transform duration-300 text-muted-foreground shrink-0",
              isExpanded ? "rotate-180" : ""
            )}
            style={{ color: isExpanded ? iconColor : collapsedIconColor || undefined }}
          >
            <svg width="16" height="16" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth={2.5}>
              <path d="M6 9l6 6 6-6" strokeLinecap="round" strokeLinejoin="round" />
            </svg>
          </span>
        )}
      </button>

      {/* Expansion Content */}
      <div
        className={cn(
          "overflow-hidden transition-all duration-300",
          isExpanded ? "max-h-[500px] opacity-100" : "max-h-0 opacity-0"
        )}
      >
        {(maintainState || isExpanded) && (
          <div className={cn("border-t border-border/60", childrenPadding)}>
            {children}
          </div>
        )}
      </div>
    </div>
  );
}

import React, { useState, useEffect } from "react";
import { cn } from "../utils";

// ─── Types ────────────────────────────────────────────────────────────────────
interface FadeTransitionProps {
  opacity: number; // 0.0 - 1.0
  duration?: number; // ms
  curve?: "ease" | "easeIn" | "easeOut" | "easeInOut" | "linear";
  child?: React.ReactNode;
  children?: React.ReactNode;
  className?: string;
  onEnd?: () => void;
}

// ─── FadeTransition ───────────────────────────────────────────────────────────
export function FadeTransition({
  opacity,
  duration = 400,
  curve = "easeInOut",
  children,
  child,
  className,
  onEnd,
}: FadeTransitionProps) {
  const curveMap: Record<string, string> = {
    ease: "ease",
    easeIn: "ease-in",
    easeOut: "ease-out",
    easeInOut: "ease-in-out",
    linear: "linear",
  };

  return (
    <div
      className={className}
      style={{
        opacity,
        transition: `opacity ${duration}ms ${curveMap[curve]}`,
      }}
      onTransitionEnd={onEnd}
    >
      {children ?? child}
    </div>
  );
}

// ─── AnimatedSwitcher ─────────────────────────────────────────────────────────
interface AnimatedSwitcherProps {
  child: React.ReactNode;
  duration?: number;
  transitionType?: "fade" | "scale" | "slide";
  className?: string;
}

export function AnimatedSwitcher({
  child,
  duration = 300,
  transitionType = "fade",
  className,
}: AnimatedSwitcherProps) {
  const [displayed, setDisplayed] = useState(child);
  const [visible, setVisible] = useState(true);

  useEffect(() => {
    setVisible(false);
    const t = setTimeout(() => {
      setDisplayed(child);
      setVisible(true);
    }, duration / 2);
    return () => clearTimeout(t);
  }, [child]);

  const transitionStyle: React.CSSProperties = {
    opacity: visible ? 1 : 0,
    transform:
      transitionType === "scale"
        ? visible ? "scale(1)" : "scale(0.85)"
        : transitionType === "slide"
        ? visible ? "translateY(0)" : "translateY(12px)"
        : undefined,
    transition: `opacity ${duration / 2}ms ease-in-out, transform ${duration / 2}ms ease-in-out`,
  };

  return (
    <div className={className} style={transitionStyle}>
      {displayed}
    </div>
  );
}

// ─── Visibility (conditional render preserving DOM) ───────────────────────────
interface VisibilityProps {
  visible: boolean;
  child: React.ReactNode;
  maintainSize?: boolean;
  maintainAnimation?: boolean;
  className?: string;
}

export function Visibility({
  visible,
  child,
  maintainSize = false,
  className,
}: VisibilityProps) {
  if (maintainSize) {
    return (
      <div
        className={className}
        style={{ visibility: visible ? "visible" : "hidden" }}
      >
        {child}
      </div>
    );
  }
  return visible ? <div className={className}>{child}</div> : null;
}

// ─── Opacity ──────────────────────────────────────────────────────────────────
interface OpacityProps {
  opacity: number;
  child?: React.ReactNode;
  children?: React.ReactNode;
  className?: string;
  alwaysIncludeSemantics?: boolean;
}

export function Opacity({ opacity, children, child, className }: OpacityProps) {
  return (
    <div className={cn("", className)} style={{ opacity }}>
      {children ?? child}
    </div>
  );
}

