import * as React from "react";
import { cn } from "../utils";

// ─── Types ───────────────────────────────────────────────────────────────────

export interface NavigationBarDestination {
  /** The icon displayed when this destination is unselected. */
  icon: React.ReactNode;
  /** The icon displayed when this destination is selected. Optional; falls back to icon. */
  selectedIcon?: React.ReactNode;
  /** The text label below the icon. */
  label: string;
  /** Whether this destination is enabled. Default true. */
  enabled?: boolean;
  /** Badge content (number or dot). */
  badge?: number | boolean;
  /** Tooltip string. */
  tooltip?: string;
}

export interface NavigationBarProps {
  /** Currently selected index. */
  selectedIndex?: number;
  /** Called when user taps a destination. */
  onDestinationSelected?: (index: number) => void;
  /** Array of destinations. */
  destinations: NavigationBarDestination[];
  /** Background color of the bar. */
  backgroundColor?: string;
  /** Elevation (shadow). Default 3. */
  elevation?: number;
  /** Height of the navigation bar. Default 80. */
  height?: number;
  /** Color used for indicator behind selected icon. */
  indicatorColor?: string;
  /** Label behavior. */
  labelBehavior?: "alwaysShow" | "alwaysHide" | "onlyShowSelected";
  /** Whether labels are shown. Overridden by labelBehavior. */
  showLabels?: boolean;
  /** Animation duration in ms. Default 200. */
  animationDuration?: number;
  className?: string;
  style?: React.CSSProperties;
  key?: React.Key;
}

/**
 * A Material 3 Navigation Bar.
 * Equivalent to Flutter's NavigationBar() widget (Material 3).
 *
 * Differs from BottomNavigationBar in that it uses an indicator pill behind
 * the selected icon instead of just a color change.
 */
export const NavigationBar = React.memo(({
  selectedIndex = 0,
  onDestinationSelected,
  destinations,
  backgroundColor,
  elevation = 3,
  height = 80,
  indicatorColor,
  labelBehavior = "alwaysShow",
  showLabels = true,
  animationDuration = 200,
  className,
  style,
}: NavigationBarProps) => {
  const resolvedBg = backgroundColor ?? "hsl(var(--card))";
  const resolvedIndicator = indicatorColor ?? "hsl(var(--primary) / 0.15)";

  const showLabel = (i: number): boolean => {
    if (labelBehavior === "alwaysHide") return false;
    if (labelBehavior === "alwaysShow") return showLabels;
    if (labelBehavior === "onlyShowSelected") return i === selectedIndex;
    return showLabels;
  };

  const shadow =
    elevation === 0
      ? "none"
      : `0 -${elevation}px ${elevation * 4}px rgba(0,0,0,0.08)`;

  return (
    <nav
      className={cn(
        "w-full flex items-stretch border-t border-border",
        className,
      )}
      style={{
        backgroundColor: resolvedBg,
        height,
        boxShadow: shadow,
        ...style,
      }}
      aria-label="Navigation bar"
    >
      {destinations.map((dest, i) => {
        const isSelected = i === selectedIndex;
        const isEnabled = dest.enabled !== false;

        return (
          <button
            key={i}
            type="button"
            disabled={!isEnabled}
            onClick={() => isEnabled && onDestinationSelected?.(i)}
            title={dest.tooltip ?? dest.label}
            aria-label={dest.label}
            aria-current={isSelected ? "page" : undefined}
            className={cn(
              "relative flex-1 flex flex-col items-center justify-center gap-1",
              "transition-all duration-200 outline-none",
              "focus-visible:ring-2 focus-visible:ring-ring focus-visible:ring-inset",
              isEnabled ? "cursor-pointer" : "cursor-not-allowed opacity-40",
            )}
          >
            {/* ── Indicator pill ──────────────────────────────────────────── */}
            <div className="relative flex items-center justify-center">
              <span
                className="absolute rounded-full transition-all"
                style={{
                  backgroundColor: isSelected ? resolvedIndicator : "transparent",
                  width: isSelected ? 64 : 32,
                  height: 32,
                  transitionDuration: `${animationDuration}ms`,
                  transitionTimingFunction: "cubic-bezier(.34,1.56,.64,1)",
                }}
                aria-hidden="true"
              />

              {/* ── Badge ─────────────────────────────────────────────────── */}
              <span className="relative z-10 flex items-center justify-center text-xl"
                style={{
                  color: isSelected
                    ? "hsl(var(--primary))"
                    : "hsl(var(--muted-foreground))",
                  transition: `color ${animationDuration}ms`,
                }}
              >
                {isSelected ? (dest.selectedIcon ?? dest.icon) : dest.icon}

                {/* Badge dot or number */}
                {dest.badge !== undefined && dest.badge !== false && (
                  <span
                    className="absolute -top-1 -right-1 flex items-center justify-center rounded-full bg-destructive text-destructive-foreground font-bold"
                    style={{
                      minWidth: typeof dest.badge === "number" && dest.badge > 0 ? 16 : 8,
                      height: typeof dest.badge === "number" && dest.badge > 0 ? 16 : 8,
                      fontSize: 9,
                      paddingLeft: typeof dest.badge === "number" && dest.badge > 0 ? 3 : 0,
                      paddingRight: typeof dest.badge === "number" && dest.badge > 0 ? 3 : 0,
                    }}
                  >
                    {typeof dest.badge === "number" && dest.badge > 0
                      ? dest.badge > 99 ? "99+" : dest.badge
                      : null}
                  </span>
                )}
              </span>
            </div>

            {/* ── Label ─────────────────────────────────────────────────────── */}
            <span
              className="text-[10px] font-medium leading-none transition-all select-none"
              style={{
                color: isSelected
                  ? "hsl(var(--primary))"
                  : "hsl(var(--muted-foreground))",
                opacity: showLabel(i) ? 1 : 0,
                maxHeight: showLabel(i) ? 20 : 0,
                transitionDuration: `${animationDuration}ms`,
                fontWeight: isSelected ? "600" : "500",
              }}
              aria-hidden={!showLabel(i)}
            >
              {dest.label}
            </span>
          </button>
        );
      })}
    </nav>
  );
});

NavigationBar.displayName = "NavigationBar";

import React from "react";
import { cn } from "../utils";

// ─── Types ────────────────────────────────────────────────────────────────────
export interface NavDrawerDestination {
  icon: React.ReactNode;
  selectedIcon?: React.ReactNode;
  label: string;
  badge?: number | string;
}

export interface NavDrawerSection {
  header?: React.ReactNode;
  destinations: NavDrawerDestination[];
}

interface NavigationDrawerProps {
  isOpen: boolean;
  onClose: () => void;
  sections?: NavDrawerSection[];
  destinations?: NavDrawerDestination[];
  selectedIndex: number;
  onDestinationSelected: (index: number) => void;
  header?: React.ReactNode;
  footer?: React.ReactNode;
  drawerWidth?: number;
  position?: "left" | "right";
  backgroundColor?: string;
  className?: string;
}

// ─── NavigationDrawer ─────────────────────────────────────────────────────────
export function NavigationDrawer({
  isOpen,
  onClose,
  sections,
  destinations,
  selectedIndex,
  onDestinationSelected,
  header,
  footer,
  drawerWidth = 304,
  position = "left",
  backgroundColor,
  className,
}: NavigationDrawerProps) {
  // Flatten all destinations for index tracking
  const allDests = sections
    ? sections.flatMap((s) => s.destinations)
    : destinations ?? [];

  let globalIndex = 0;

  return (
    <>
      {/* Backdrop */}
      {isOpen && (
        <div
          className="fixed inset-0 z-40 bg-black/50 backdrop-blur-sm transition-opacity"
          onClick={onClose}
        />
      )}

      {/* Drawer Panel */}
      <div
        className={cn(
          "fixed top-0 bottom-0 z-50 flex flex-col border-border bg-card shadow-2xl transition-transform duration-300",
          position === "left" ? "left-0 border-r rounded-r-2xl" : "right-0 border-l rounded-l-2xl",
          isOpen
            ? "translate-x-0"
            : position === "left"
            ? "-translate-x-full"
            : "translate-x-full",
          className
        )}
        style={{ width: drawerWidth, backgroundColor: backgroundColor || undefined }}
      >
        {/* Header */}
        {header && (
          <div className="p-5 border-b border-border shrink-0">
            {header}
          </div>
        )}

        {/* Destinations / Sections */}
        <div className="flex-1 overflow-y-auto p-3 space-y-1">
          {sections ? (
            sections.map((section, sIdx) => (
              <div key={sIdx}>
                {section.header && (
                  <div className="px-3 py-2 text-[10px] font-bold uppercase tracking-wider text-muted-foreground">
                    {section.header}
                  </div>
                )}
                {section.destinations.map((dest) => {
                  const idx = globalIndex++;
                  const isSelected = idx === selectedIndex;
                  return (
                    <DrawerDestinationItem
                      key={idx}
                      dest={dest}
                      isSelected={isSelected}
                      onClick={() => { onDestinationSelected(idx); onClose(); }}
                    />
                  );
                })}
              </div>
            ))
          ) : (
            allDests.map((dest, i) => (
              <DrawerDestinationItem
                key={i}
                dest={dest}
                isSelected={i === selectedIndex}
                onClick={() => { onDestinationSelected(i); onClose(); }}
              />
            ))
          )}
        </div>

        {/* Footer */}
        {footer && (
          <div className="p-4 border-t border-border shrink-0">
            {footer}
          </div>
        )}
      </div>
    </>
  );
}

// ─── Internal: Drawer Destination Item ────────────────────────────────────────
function DrawerDestinationItem({
  dest,
  isSelected,
  onClick,
}: {
  dest: NavDrawerDestination;
  isSelected: boolean;
  onClick: () => void;
}) {
  return (
    <button
      onClick={onClick}
      className={cn(
        "w-full flex items-center gap-3 px-4 py-3 rounded-xl text-sm font-medium transition-all",
        isSelected
          ? "bg-primary/10 text-primary font-semibold"
          : "text-muted-foreground hover:bg-accent hover:text-foreground"
      )}
    >
      <span className="text-lg shrink-0">
        {isSelected && dest.selectedIcon ? dest.selectedIcon : dest.icon}
      </span>
      <span className="flex-1 text-left">{dest.label}</span>
      {dest.badge !== undefined && (
        <span className="min-w-[18px] h-[18px] bg-red-500 text-white text-[9px] font-bold rounded-full flex items-center justify-center px-1">
          {dest.badge}
        </span>
      )}
    </button>
  );
}

