export interface PaddingProps
  extends React.HTMLAttributes<HTMLDivElement>, SizeProps {
  padding: EdgeInsetsInput;
  key?: React.Key;
}

/**
 * A widget that insets its child by the given padding.
 * Equivalent to Flutter's Padding() widget.
 */
export const Padding = React.forwardRef<HTMLDivElement, PaddingProps>(
  (
    {
      padding,
      width,
      height,
      minWidth,
      maxWidth,
      minHeight,
      maxHeight,
      children,
      className,
      style,
      ...props
    },
    ref,
  ) => {
    return (
      <div
        ref={ref}
        className={cn(className)}
        style={{
          ...edgeInsetsToStyle(padding, "padding"),
          ...sizePropsToStyle({
            width,
            height,
            minWidth,
            maxWidth,
            minHeight,
            maxHeight,
          }),
          ...style,
        }}
        {...props}
      >
        {children}
      </div>
    );
  },
);

Padding.displayName = "Padding";

/**
 * PageView — a horizontally (or vertically) paged scroll container.
 * Equivalent to Flutter's PageView() widget.
 *
 * Features:
 *  - Snap-to-page scrolling via CSS scroll-snap
 *  - Controlled (page prop + onPageChanged) or uncontrolled
 *  - Horizontal or vertical scroll direction
 *  - Reverse direction
 *  - Physics: "never" disables swiping (programmatic only)
 *  - PageController-style imperative API via ref
 *  - Optional dot indicator
 *  - itemBuilder + itemCount or children
 *  - onPageChanged callback
 *  - viewportFraction (< 1 shows adjacent pages)
 *  - allowImplicitScrolling (keeps adjacent pages alive)
 */
import * as React from "react";
import { cn } from "../utils";
import type { Color, SizeInput } from "./flutter-style";
import { sizeToCss } from "./flutter-style";

// ─────────────────────────────────────────────────────────────────────────────
// PageController (imperative handle)
// ─────────────────────────────────────────────────────────────────────────────
export interface PageController {
  /** Animate to a page index. */
  animateToPage: (page: number, durationMs?: number) => void;
  /** Jump to a page index instantly. */
  jumpToPage: (page: number) => void;
  /** Animate to the next page. */
  nextPage: (durationMs?: number) => void;
  /** Animate to the previous page. */
  previousPage: (durationMs?: number) => void;
  /** Current page index (may be fractional during animation). */
  readonly page: number;
}

/** Create a ref-based PageController to pass to PageView. */
export function usePageController(): React.RefObject<PageController | null> {
  return React.useRef<PageController | null>(null);
}

// ─────────────────────────────────────────────────────────────────────────────
// Props
// ─────────────────────────────────────────────────────────────────────────────
export interface PageViewProps {
  /** Page widgets. Alternative to itemBuilder + itemCount. */
  children?: React.ReactNode;
  /** Number of pages when using itemBuilder. */
  itemCount?: number;
  /** Builder called with page index. */
  itemBuilder?: (index: number) => React.ReactNode;
  /** Controlled current page (0-based). */
  page?: number;
  /** Called when the visible page changes. */
  onPageChanged?: (page: number) => void;
  /** Scroll direction. Default "horizontal". */
  scrollDirection?: "horizontal" | "vertical";
  /** Reverse the scroll direction. */
  reverse?: boolean;
  /**
   * Fraction of the viewport each page occupies.
   * 1.0 = full width (default). 0.9 shows a peek of adjacent pages.
   */
  viewportFraction?: number;
  /**
   * Scroll physics.
   * "page"   — snap to pages (default)
   * "never"  — no user scrolling (programmatic only)
   * "free"   — free scroll, no snap
   */
  physics?: "page" | "never" | "free";
  /** Whether to show the built-in dot indicator. */
  showIndicator?: boolean;
  /** Color of the active dot. */
  indicatorActiveColor?: Color;
  /** Color of inactive dots. */
  indicatorInactiveColor?: Color;
  /** Size of each dot in px. Default 8. */
  indicatorDotSize?: number;
  /** Gap between dots in px. Default 6. */
  indicatorSpacing?: number;
  /** Explicit width of the PageView container. */
  width?: SizeInput;
  /** Explicit height of the PageView container. */
  height?: SizeInput;
  /** Imperative controller ref. */
  controller?: React.RefObject<PageController | null>;
  className?: string;
  style?: React.CSSProperties;
  key?: React.Key;
}

// ─────────────────────────────────────────────────────────────────────────────
// Component
// ─────────────────────────────────────────────────────────────────────────────
export const PageView = React.forwardRef<HTMLDivElement, PageViewProps>(
  (
    {
      children,
      itemCount,
      itemBuilder,
      page: controlledPage,
      onPageChanged,
      scrollDirection = "horizontal",
      reverse = false,
      viewportFraction = 1,
      physics = "page",
      showIndicator = false,
      indicatorActiveColor,
      indicatorInactiveColor,
      indicatorDotSize = 8,
      indicatorSpacing = 6,
      width,
      height,
      controller,
      className,
      style,
    },
    ref,
  ) => {
    const isHorizontal = scrollDirection === "horizontal";
    const scrollRef = React.useRef<HTMLDivElement>(null);
    const [currentPage, setCurrentPage] = React.useState(controlledPage ?? 0);
    const isScrolling = React.useRef(false);
    void isScrolling; // reserved for future gesture-cancel logic

    // Build pages array
    const pages = React.useMemo(() => {
      if (itemBuilder && itemCount !== undefined) {
        return Array.from({ length: itemCount }, (_, i) => itemBuilder(i));
      }
      return React.Children.toArray(children);
    }, [children, itemBuilder, itemCount]);

    const pageCount = pages.length;

    // ── Scroll to page ──────────────────────────────────────
    const scrollToPage = React.useCallback(
      (index: number, smooth = true) => {
        const el = scrollRef.current;
        if (!el || index < 0 || index >= pageCount) return;
        const pageSize = isHorizontal ? el.clientWidth : el.clientHeight;
        const offset = index * pageSize * viewportFraction;
        if (isHorizontal) {
          el.scrollTo({
            left: reverse ? -offset : offset,
            behavior: smooth ? "smooth" : "instant",
          });
        } else {
          el.scrollTo({
            top: reverse ? -offset : offset,
            behavior: smooth ? "smooth" : "instant",
          });
        }
      },
      [isHorizontal, reverse, viewportFraction, pageCount],
    );

    // ── Sync controlled page ────────────────────────────────
    React.useEffect(() => {
      if (controlledPage !== undefined && controlledPage !== currentPage) {
        setCurrentPage(controlledPage);
        scrollToPage(controlledPage);
      }
    }, [controlledPage]); // eslint-disable-line react-hooks/exhaustive-deps

    // ── Expose imperative controller ────────────────────────
    React.useEffect(() => {
      if (!controller) return;
      (controller as any).current = {
        animateToPage: (p, _ms = 300) => {
          scrollToPage(p, true);
          setCurrentPage(p);
        },
        jumpToPage: (p) => {
          scrollToPage(p, false);
          setCurrentPage(p);
        },
        nextPage: (_ms) => {
          const next = Math.min(currentPage + 1, pageCount - 1);
          scrollToPage(next, true);
          setCurrentPage(next);
        },
        previousPage: (_ms) => {
          const prev = Math.max(currentPage - 1, 0);
          scrollToPage(prev, true);
          setCurrentPage(prev);
        },
        get page() {
          return currentPage;
        },
      };
    }, [controller, currentPage, pageCount, scrollToPage]);

    // ── Detect page from scroll position ───────────────────
    const handleScroll = React.useCallback(() => {
      const el = scrollRef.current;
      if (!el) return;
      const pageSize = isHorizontal ? el.clientWidth : el.clientHeight;
      if (pageSize === 0) return;
      const scrollPos = isHorizontal ? el.scrollLeft : el.scrollTop;
      const newPage = Math.round(scrollPos / (pageSize * viewportFraction));
      const clamped = Math.max(0, Math.min(newPage, pageCount - 1));
      if (clamped !== currentPage) {
        setCurrentPage(clamped);
        onPageChanged?.(clamped);
      }
    }, [isHorizontal, viewportFraction, pageCount, currentPage, onPageChanged]);

    // ── Dot indicator ───────────────────────────────────────
    const dots = showIndicator && pageCount > 1 && (
      <div
        className="flex items-center justify-center"
        style={{
          gap: indicatorSpacing,
          padding: "8px 0",
        }}
        aria-label="Page indicator"
      >
        {Array.from({ length: pageCount }, (_, i) => (
          <button
            key={i}
            type="button"
            aria-label={`Go to page ${i + 1}`}
            aria-current={i === currentPage ? "true" : undefined}
            onClick={() => {
              scrollToPage(i);
              setCurrentPage(i);
              onPageChanged?.(i);
            }}
            style={{
              width:
                i === currentPage ? indicatorDotSize * 2.5 : indicatorDotSize,
              height: indicatorDotSize,
              borderRadius: indicatorDotSize,
              backgroundColor:
                i === currentPage
                  ? (indicatorActiveColor ?? "var(--primary)")
                  : (indicatorInactiveColor ?? "var(--muted-foreground)"),
              opacity: i === currentPage ? 1 : 0.35,
              border: "none",
              padding: 0,
              cursor: "pointer",
              transition:
                "width 250ms cubic-bezier(.4,0,.2,1), opacity 250ms, background-color 250ms",
            }}
          />
        ))}
      </div>
    );

    const pageStyle: React.CSSProperties = {
      flexShrink: 0,
      width: isHorizontal ? `${viewportFraction * 100}%` : "100%",
      height: isHorizontal ? "100%" : `${viewportFraction * 100}%`,
      scrollSnapAlign: "start",
    };

    return (
      <div
        ref={ref}
        className={cn("flex flex-col", className)}
        style={{
          width: sizeToCss(width),
          height: sizeToCss(height),
          ...style,
        }}
      >
        {/* Scroll container */}
        <div
          ref={scrollRef}
          onScroll={handleScroll}
          className={cn(
            "flex flex-1 min-h-0",
            isHorizontal
              ? reverse
                ? "flex-row-reverse"
                : "flex-row"
              : reverse
                ? "flex-col-reverse"
                : "flex-col",
            physics === "never" && "overflow-hidden",
            physics !== "never" &&
              (isHorizontal
                ? "overflow-x-auto overflow-y-hidden"
                : "overflow-y-auto overflow-x-hidden"),
          )}
          style={{
            scrollSnapType:
              physics === "page"
                ? isHorizontal
                  ? "x mandatory"
                  : "y mandatory"
                : physics === "free"
                  ? isHorizontal
                    ? "x proximity"
                    : "y proximity"
                  : undefined,
            scrollBehavior: "smooth",
            // Hide scrollbar
            scrollbarWidth: "none",
            msOverflowStyle: "none",
          }}
        >
          {pages.map((page, i) => (
            <div
              key={i}
              style={pageStyle}
              aria-hidden={i !== currentPage ? true : undefined}
            >
              {page}
            </div>
          ))}
        </div>

        {/* Dot indicator below pages */}
        {dots}
      </div>
    );
  },
);

PageView.displayName = "PageView";

import * as React from "react";
import * as ReactDOM from "react-dom";
import { cn } from "../utils";

// ─── Types ───────────────────────────────────────────────────────────────────

export interface PopupMenuEntry<T> {
  value?: T;
  child: React.ReactNode;
  enabled?: boolean;
  /** Divider instead of an item — omit value/child for a pure divider. */
  isDivider?: boolean;
  onTap?: () => void;
  height?: number;
  padding?: { top?: number; right?: number; bottom?: number; left?: number };
}

export interface PopupMenuButtonProps<T> {
  /** The icon or widget that triggers the menu. Default: ⋮ icon. */
  child?: React.ReactNode;
  /** Icon to show (alternative to child). */
  icon?: React.ReactNode;
  /** Items to display in the popup menu. */
  itemBuilder: (context: null) => PopupMenuEntry<T>[];
  /** Called when an item is selected. */
  onSelected?: (value: T) => void;
  /** Called when the menu is cancelled without selection. */
  onCanceled?: () => void;
  /** Tooltip for the button. */
  tooltip?: string;
  /** Elevation of the popup menu. Default 8. */
  elevation?: number;
  /** Background color of the popup. */
  color?: string;
  /** Whether the button is enabled. */
  enabled?: boolean;
  /** Padding inside the button. Default 8px. */
  padding?: number;
  /** Icon size. Default 24. */
  iconSize?: number;
  /** Position to offset the menu. */
  offset?: { x?: number; y?: number };
  /** Which side to prefer opening on. */
  position?: "over" | "under";
  className?: string;
  style?: React.CSSProperties;
  key?: React.Key;
}

// Stable more-vert SVG
const MoreVertIcon = (
  <svg
    viewBox="0 0 24 24"
    width={20}
    height={20}
    fill="currentColor"
    aria-hidden="true"
  >
    <circle cx="12" cy="5"  r="1.5" />
    <circle cx="12" cy="12" r="1.5" />
    <circle cx="12" cy="19" r="1.5" />
  </svg>
);

const CheckIcon = (
  <svg viewBox="0 0 24 24" width={14} height={14} fill="none" stroke="currentColor" strokeWidth={2.5}>
    <path d="M20 6L9 17l-5-5" strokeLinecap="round" strokeLinejoin="round" />
  </svg>
);

/**
 * A material design popup menu button.
 * Equivalent to Flutter's PopupMenuButton<T>() widget.
 *
 * Renders a trigger (usually ⋮) and shows a portal menu on tap.
 */
export function PopupMenuButton<T>({
  child,
  icon,
  itemBuilder,
  onSelected,
  onCanceled,
  tooltip,
  elevation = 8,
  color,
  enabled = true,
  padding = 8,
  iconSize = 24,
  offset,
  position = "under",
  className,
  style,
}: PopupMenuButtonProps<T>) {
  const [open, setOpen] = React.useState(false);
  const [menuStyle, setMenuStyle] = React.useState<React.CSSProperties>({});
  const triggerRef = React.useRef<HTMLButtonElement>(null);
  const menuRef = React.useRef<HTMLDivElement>(null);

  const items = React.useMemo(() => itemBuilder(null), [itemBuilder]);

  const openMenu = React.useCallback(() => {
    if (!enabled) return;
    const rect = triggerRef.current?.getBoundingClientRect();
    if (!rect) return;

    const spaceBelow = window.innerHeight - rect.bottom;
    const openUp = position === "over" || (spaceBelow < 200 && rect.top > spaceBelow);

    const menuWidth = 180;
    let left = rect.left;
    if (left + menuWidth > window.innerWidth) {
      left = rect.right - menuWidth;
    }

    setMenuStyle({
      position: "fixed",
      zIndex: 9999,
      minWidth: menuWidth,
      left: left + (offset?.x ?? 0),
      ...(openUp
        ? { bottom: window.innerHeight - rect.top + (offset?.y ?? 0) }
        : { top: rect.bottom + (offset?.y ?? 4) }),
      backgroundColor: color ?? "hsl(var(--popover))",
      borderRadius: 8,
      border: "1px solid hsl(var(--border))",
      boxShadow: `0 ${elevation}px ${elevation * 3}px rgba(0,0,0,0.18)`,
      overflow: "hidden",
    });
    setOpen(true);
  }, [enabled, position, offset, color, elevation]);

  // Close on outside click / Escape
  React.useEffect(() => {
    if (!open) return;
    const handleClick = (e: MouseEvent) => {
      if (
        menuRef.current && !menuRef.current.contains(e.target as Node) &&
        triggerRef.current && !triggerRef.current.contains(e.target as Node)
      ) {
        setOpen(false);
        onCanceled?.();
      }
    };
    const handleKey = (e: KeyboardEvent) => {
      if (e.key === "Escape") { setOpen(false); onCanceled?.(); }
    };
    document.addEventListener("mousedown", handleClick);
    document.addEventListener("keydown", handleKey);
    return () => {
      document.removeEventListener("mousedown", handleClick);
      document.removeEventListener("keydown", handleKey);
    };
  }, [open, onCanceled]);

  const trigger = child ?? icon ?? MoreVertIcon;

  return (
    <>
      <button
        ref={triggerRef}
        type="button"
        disabled={!enabled}
        onClick={open ? () => setOpen(false) : openMenu}
        title={tooltip}
        aria-haspopup="menu"
        aria-expanded={open}
        className={cn(
          "inline-flex items-center justify-center rounded-full transition-colors duration-150",
          "hover:bg-accent/60 active:bg-accent focus-visible:outline-none focus-visible:ring-2 focus-visible:ring-ring",
          !enabled && "opacity-50 cursor-not-allowed",
          className,
        )}
        style={{
          padding,
          width: iconSize + padding * 2,
          height: iconSize + padding * 2,
          ...style,
        }}
      >
        {trigger}
      </button>

      {open && ReactDOM.createPortal(
        <div
          ref={menuRef}
          role="menu"
          style={menuStyle}
          className="py-1 animate-in fade-in zoom-in-95 duration-100"
        >
          {items.map((item, i) => {
            if (item.isDivider) {
              return (
                <div
                  key={i}
                  role="separator"
                  className="h-px bg-border my-1 mx-3"
                  aria-hidden="true"
                />
              );
            }
            const itemEnabled = item.enabled !== false;
            return (
              <div
                key={i}
                role="menuitem"
                tabIndex={itemEnabled ? 0 : -1}
                aria-disabled={!itemEnabled}
                className={cn(
                  "flex items-center gap-2.5 px-4 text-sm text-popover-foreground transition-colors select-none",
                  itemEnabled
                    ? "cursor-pointer hover:bg-accent hover:text-accent-foreground"
                    : "opacity-40 cursor-not-allowed",
                )}
                style={{
                  minHeight: item.height ?? 44,
                  paddingTop: item.padding?.top ?? 0,
                  paddingBottom: item.padding?.bottom ?? 0,
                  paddingLeft: item.padding?.left ?? 16,
                  paddingRight: item.padding?.right ?? 16,
                }}
                onClick={() => {
                  if (!itemEnabled) return;
                  item.onTap?.();
                  if (item.value !== undefined) {
                    onSelected?.(item.value);
                  }
                  setOpen(false);
                }}
                onKeyDown={(e) => {
                  if (!itemEnabled) return;
                  if (e.key === "Enter" || e.key === " ") {
                    e.preventDefault();
                    item.onTap?.();
                    if (item.value !== undefined) onSelected?.(item.value);
                    setOpen(false);
                  }
                }}
              >
                {item.child}
              </div>
            );
          })}
        </div>,
        document.body,
      )}
    </>
  );
}

PopupMenuButton.displayName = "PopupMenuButton";

