}

import * as React from "react";
import { cn } from "../utils";

export interface RefreshIndicatorProps {
  /** The scrollable child that can be pulled to refresh. */
  child?: React.ReactNode;
  /** Alternate way to provide React children. */
  children?: React.ReactNode;
  /**
   * Async function called when a refresh is triggered.
   * The indicator stays visible until the Future completes.
   */
  onRefresh: () => Promise<void>;
  /**
   * Displacement from the top before the refresh triggers.
   * Equivalent to Flutter's displacement prop. Default 40.
   */
  displacement?: number;
  /** Color of the indicator circle. */
  color?: string;
  /** Background color of the indicator badge. */
  backgroundColor?: string;
  /** Stroke width of the spinner. Default 2.5. */
  strokeWidth?: number;
  /** Size of the circular indicator. Default 36. */
  indicatorSize?: number;
  /**
   * How far the user must drag before the refresh is triggered.
   * Default 80px.
   */
  triggerMode?: "onEdge" | "anywhere";
  className?: string;
  style?: React.CSSProperties;
  key?: React.Key;
}

/** Spinner SVG — stable reference */
const Spinner = ({ color, size, strokeWidth }: { color: string; size: number; strokeWidth: number }) => (
  <svg
    width={size}
    height={size}
    viewBox="0 0 24 24"
    fill="none"
    className="animate-spin"
    aria-label="Loading"
  >
    <circle
      cx="12"
      cy="12"
      r="10"
      stroke={color}
      strokeWidth={strokeWidth}
      strokeOpacity={0.25}
    />
    <path
      d="M12 2a10 10 0 0 1 10 10"
      stroke={color}
      strokeWidth={strokeWidth}
      strokeLinecap="round"
    />
  </svg>
);

/**
 * A widget that supports the Material "swipe down to refresh" idiom.
 * Equivalent to Flutter's RefreshIndicator() widget.
 *
 * The `onRefresh` callback must return a Promise; the spinner stays
 * visible until that promise resolves.
 *
 * Note: Since browsers block native pull-to-refresh, this component
 * implements a CSS overscroll / pointer-drag approach.
 */
export const RefreshIndicator = React.forwardRef<HTMLDivElement, RefreshIndicatorProps>(
  (
    {
      child,
      children,
      onRefresh,
      displacement = 40,
      color,
      backgroundColor,
      strokeWidth = 2.5,
      indicatorSize = 36,
      triggerMode = "onEdge",
      className,
      style,
    },
    ref,
  ) => {
    const containerRef = React.useRef<HTMLDivElement>(null);
    const [pullY, setPullY] = React.useState(0);
    const [isRefreshing, setIsRefreshing] = React.useState(false);
    const [isDragging, setIsDragging] = React.useState(false);
    const startYRef = React.useRef(0);
    const MAX_PULL = displacement + 60;
    const TRIGGER_THRESHOLD = displacement;

    const resolvedColor = color ?? "hsl(var(--primary))";
    const resolvedBg = backgroundColor ?? "hsl(var(--background))";

    const progress = Math.min(1, pullY / TRIGGER_THRESHOLD);
    const indicatorOpacity = pullY > 0 ? Math.min(1, progress * 1.5) : 0;
    const indicatorTranslate = -indicatorSize - 8 + Math.min(pullY, MAX_PULL);

    // ── Touch / Pointer handling ──────────────────────────────────────────────

    const handlePointerDown = (e: React.PointerEvent) => {
      if (isRefreshing) return;
      const el = containerRef.current;
      if (!el) return;
      // Only allow pull when already at the top
      if (triggerMode === "onEdge" && el.scrollTop > 0) return;
      startYRef.current = e.clientY;
      setIsDragging(true);
      el.setPointerCapture(e.pointerId);
    };

    const handlePointerMove = (e: React.PointerEvent) => {
      if (!isDragging || isRefreshing) return;
      const el = containerRef.current;
      if (!el) return;
      if (triggerMode === "onEdge" && el.scrollTop > 0) {
        setIsDragging(false);
        setPullY(0);
        return;
      }
      const delta = Math.max(0, e.clientY - startYRef.current);
      // Apply rubber-band damping
      const dampened = delta > MAX_PULL ? MAX_PULL + (delta - MAX_PULL) * 0.2 : delta;
      setPullY(Math.min(dampened, MAX_PULL * 1.2));
    };

    const handlePointerUp = React.useCallback(async () => {
      if (!isDragging) return;
      setIsDragging(false);
      if (pullY >= TRIGGER_THRESHOLD) {
        setIsRefreshing(true);
        setPullY(TRIGGER_THRESHOLD); // snap to trigger position
        try {
          await onRefresh();
        } finally {
          setIsRefreshing(false);
          setPullY(0);
        }
      } else {
        setPullY(0);
      }
    }, [isDragging, pullY, TRIGGER_THRESHOLD, onRefresh]);

    const showIndicator = pullY > 0 || isRefreshing;
    const indicatorRotation = isRefreshing ? undefined : `rotate(${progress * 270}deg)`;

    return (
      <div
        ref={(el) => {
          (containerRef as React.MutableRefObject<HTMLDivElement | null>).current = el;
          if (typeof ref === "function") ref(el!);
          else if (ref) (ref as React.MutableRefObject<HTMLDivElement | null>).current = el;
        }}
        className={cn("relative overflow-y-auto overflow-x-hidden", className)}
        style={{ touchAction: "pan-x", ...style }}
        onPointerDown={handlePointerDown}
        onPointerMove={handlePointerMove}
        onPointerUp={handlePointerUp}
        onPointerCancel={handlePointerUp}
      >
        {/* ── Indicator badge ────────────────────────────────────────────── */}
        <div
          aria-live="polite"
          aria-busy={isRefreshing}
          className="pointer-events-none absolute left-1/2 z-50 flex items-center justify-center rounded-full shadow-lg"
          style={{
            width: indicatorSize + 8,
            height: indicatorSize + 8,
            backgroundColor: resolvedBg,
            border: `1px solid hsl(var(--border))`,
            transform: `translateX(-50%) translateY(${indicatorTranslate}px)`,
            opacity: indicatorOpacity,
            top: 8,
            transition: isRefreshing || isDragging
              ? "opacity 0.15s"
              : "transform 0.35s cubic-bezier(.34,1.56,.64,1), opacity 0.25s",
          }}
        >
          {showIndicator && (
            <div
              style={{
                transform: isRefreshing ? undefined : indicatorRotation,
                transition: isRefreshing ? undefined : "transform 0.05s",
              }}
            >
              <Spinner color={resolvedColor} size={indicatorSize - 8} strokeWidth={strokeWidth} />
            </div>
          )}
        </div>

        {/* ── Scrollable content ─────────────────────────────────────────── */}
        <div
          style={{
            transform: isDragging || isRefreshing
              ? `translateY(${Math.min(pullY, MAX_PULL)}px)`
              : "translateY(0)",
            transition: isDragging ? "none" : "transform 0.35s cubic-bezier(.34,1.56,.64,1)",
            willChange: "transform",
          }}
        >
          {children ?? child}
        </div>
      </div>
    );
  },
);

RefreshIndicator.displayName = "RefreshIndicator";

import React, { useState, useRef, useCallback } from "react";
import { cn } from "../utils";

// ─── Types ────────────────────────────────────────────────────────────────────
interface ReorderableListProps<T> {
  items: T[];
  onReorder: (items: T[]) => void;
  itemBuilder: (item: T, index: number, isDragging: boolean) => React.ReactNode;
  keyExtractor: (item: T) => string;
  proxyDecorator?: (child: React.ReactNode) => React.ReactNode;
  padding?: string;
  className?: string;
}

// ─── ReorderableListView ──────────────────────────────────────────────────────
export function ReorderableListView<T>({
  items,
  onReorder,
  itemBuilder,
  keyExtractor,
  proxyDecorator,
  padding,
  className,
}: ReorderableListProps<T>) {
  const [draggingIndex, setDraggingIndex] = useState<number | null>(null);
  const [dragOverIndex, setDragOverIndex] = useState<number | null>(null);
  const itemsRef = useRef(items);
  itemsRef.current = items;

  const handleDragStart = (index: number) => {
    setDraggingIndex(index);
  };

  const handleDragOver = (e: React.DragEvent, index: number) => {
    e.preventDefault();
    setDragOverIndex(index);
  };

  const handleDrop = (targetIndex: number) => {
    if (draggingIndex === null || draggingIndex === targetIndex) {
      setDraggingIndex(null);
      setDragOverIndex(null);
      return;
    }

    const newItems = [...itemsRef.current];
    const [removed] = newItems.splice(draggingIndex, 1);
    newItems.splice(targetIndex, 0, removed);
    onReorder(newItems);
    setDraggingIndex(null);
    setDragOverIndex(null);
  };

  const handleDragEnd = () => {
    setDraggingIndex(null);
    setDragOverIndex(null);
  };

  return (
    <div className={cn("flex flex-col", padding, className)}>
      {items.map((item, index) => {
        const isDragging = index === draggingIndex;
        const isDragOver = index === dragOverIndex;
        const key = keyExtractor(item);

        return (
          <div
            key={key}
            draggable
            onDragStart={() => handleDragStart(index)}
            onDragOver={(e) => handleDragOver(e, index)}
            onDrop={() => handleDrop(index)}
            onDragEnd={handleDragEnd}
            className={cn(
              "transition-all duration-150 group",
              isDragging ? "opacity-40 scale-95" : "opacity-100",
              isDragOver && !isDragging ? "border-t-2 border-primary" : ""
            )}
          >
            <div className="flex items-center gap-2">
              {/* Drag handle */}
              <div className="cursor-grab active:cursor-grabbing p-1 text-muted-foreground/40 group-hover:text-muted-foreground transition-colors shrink-0">
                <svg width="14" height="14" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth={2}>
                  <circle cx="9" cy="5" r="1" fill="currentColor" />
                  <circle cx="9" cy="12" r="1" fill="currentColor" />
                  <circle cx="9" cy="19" r="1" fill="currentColor" />
                  <circle cx="15" cy="5" r="1" fill="currentColor" />
                  <circle cx="15" cy="12" r="1" fill="currentColor" />
                  <circle cx="15" cy="19" r="1" fill="currentColor" />
                </svg>
              </div>
              <div className="flex-1">
                {itemBuilder(item, index, isDragging)}
              </div>
            </div>
          </div>
        );
      })}
    </div>
  );
}

import * as React from "react";
import { cn } from "../utils";

// ─── TextSpan ─────────────────────────────────────────────────────────────────

export interface TextStyle {
  color?: string;
  fontSize?: number | string;
  fontWeight?: "100" | "200" | "300" | "400" | "500" | "600" | "700" | "800" | "900" |
    "thin" | "extraLight" | "light" | "normal" | "medium" | "semiBold" | "bold" | "extraBold" | "black";
  fontStyle?: "normal" | "italic";
  letterSpacing?: number | string;
  wordSpacing?: number | string;
  decoration?: "none" | "underline" | "overline" | "line-through";
  decorationColor?: string;
  decorationStyle?: "solid" | "dashed" | "dotted" | "double";
  backgroundColor?: string;
  fontFamily?: string;
  height?: number; // lineHeight multiplier
  shadows?: { color: string; offsetX?: number; offsetY?: number; blurRadius?: number }[];
}

export interface TextSpanProps {
  /** The text content of this span. */
  text?: string;
  /** Nested child spans for inline mixed styles. */
  children?: TextSpanProps | TextSpanProps[];
  /** Text style applied to this span and its children. */
  style?: TextStyle;
  /** Called when this span is tapped. Makes it a recognizer span. */
  onTap?: () => void;
  /** Semantic label for accessibility. */
  semanticsLabel?: string;
  /** Whether to spell-check this span. */
  spellOut?: boolean;
}

const fontWeightMap: Record<string, string> = {
  thin: "100", extraLight: "200", light: "300", normal: "400",
  medium: "500", semiBold: "600", bold: "700", extraBold: "800", black: "900",
};

function textStyleToCSS(style?: TextStyle): React.CSSProperties {
  if (!style) return {};
  const fw = style.fontWeight
    ? fontWeightMap[style.fontWeight] ?? style.fontWeight
    : undefined;

  const shadows = style.shadows?.map(
    (s) => `${s.offsetX ?? 0}px ${s.offsetY ?? 0}px ${s.blurRadius ?? 0}px ${s.color}`
  ).join(", ");

  return {
    color: style.color,
    fontSize: typeof style.fontSize === "number" ? `${style.fontSize}px` : style.fontSize,
    fontWeight: fw,
    fontStyle: style.fontStyle,
    letterSpacing: typeof style.letterSpacing === "number" ? `${style.letterSpacing}px` : style.letterSpacing,
    wordSpacing: typeof style.wordSpacing === "number" ? `${style.wordSpacing}px` : style.wordSpacing,
    textDecoration: style.decoration === "none" ? "none" : style.decoration,
    textDecorationColor: style.decorationColor,
    textDecorationStyle: style.decorationStyle,
    backgroundColor: style.backgroundColor,
    fontFamily: style.fontFamily,
    lineHeight: style.height,
    textShadow: shadows,
  };
}

/** Recursively render a TextSpan tree into React <span> elements. */
function renderSpan(span: TextSpanProps, key?: string | number): React.ReactNode {
  const css = textStyleToCSS(span.style);
  const isInteractive = !!span.onTap;
  const childrenArray = span.children
    ? (Array.isArray(span.children) ? span.children : [span.children])
    : [];

  return (
    <span
      key={key}
      style={css}
      title={span.semanticsLabel}
      onClick={span.onTap}
      className={cn(
        isInteractive && "cursor-pointer hover:opacity-80 transition-opacity",
      )}
      role={isInteractive ? "button" : undefined}
      tabIndex={isInteractive ? 0 : undefined}
      onKeyDown={isInteractive ? (e) => { if (e.key === "Enter" || e.key === " ") span.onTap!(); } : undefined}
    >
      {span.text}
      {childrenArray.map((child, i) => renderSpan(child, i))}
    </span>
  );
}

// ─── RichText ─────────────────────────────────────────────────────────────────

export interface RichTextProps {
  /** The root TextSpan, which may contain nested children. */
  text: TextSpanProps;
  /** Text alignment. */
  textAlign?: "left" | "center" | "right" | "justify";
  /** Max lines before overflow. */
  maxLines?: number;
  /** How overflow is handled. */
  overflow?: "ellipsis" | "clip" | "visible";
  /** Text direction. */
  textDirection?: "ltr" | "rtl";
  /** Soft-wrap toggle. */
  softWrap?: boolean;
  /** Scale factor for text. */
  textScaleFactor?: number;
  className?: string;
  style?: React.CSSProperties;
  key?: React.Key;
}

/**
 * A paragraph of rich text.
 * Equivalent to Flutter's RichText() widget + TextSpan() API.
 *
 * Usage:
 * ```tsx
 * <RichText
 *   text={{
 *     text: "Hello ",
 *     style: { fontSize: 16 },
 *     children: [
 *       { text: "World", style: { color: "#8b5cf6", fontWeight: "bold" } },
 *       { text: "! Click me", style: { color: "#3b82f6", decoration: "underline" }, onTap: () => {} },
 *     ]
 *   }}
 * />
 * ```
 */
export const RichText = React.forwardRef<HTMLParagraphElement, RichTextProps>(
  (
    {
      text,
      textAlign,
      maxLines,
      overflow = "visible",
      textDirection = "ltr",
      softWrap = true,
      textScaleFactor = 1,
      className,
      style,
    },
    ref,
  ) => {
    const overflowStyle: React.CSSProperties =
      maxLines
        ? {
            overflow: "hidden",
            textOverflow: overflow === "ellipsis" ? "ellipsis" : "clip",
            display: "-webkit-box",
            WebkitLineClamp: maxLines,
            WebkitBoxOrient: "vertical" as const,
          }
        : overflow === "clip"
          ? { overflow: "hidden" }
          : {};

    return (
      <p
        ref={ref}
        dir={textDirection}
        className={cn("m-0", className)}
        style={{
          textAlign,
          fontSize: textScaleFactor !== 1 ? `${textScaleFactor}em` : undefined,
          whiteSpace: softWrap ? "normal" : "nowrap",
          ...overflowStyle,
          ...style,
        }}
      >
        {renderSpan(text)}
      </p>
    );
  },
);

RichText.displayName = "RichText";

// ─── Re-export TextSpan as a builder helper ───────────────────────────────────

/** Helper to construct a TextSpan descriptor object (mirrors Dart syntax). */
export function TextSpan(props: TextSpanProps): TextSpanProps {
  return props;
}

import * as React from "react";
import { cn } from "../utils";
import {
