          mainAxisAlignment,
          crossAxisAlignment,
          mainAxisSize === MainAxisSize.max ? "w-full" : "w-auto",
          className,
        )}
        style={{
          gap: sizeToCss(gap),
          padding: sizeToCss(padding),
