import * as React from "react";
import { cn } from "../utils";
import { Alignment } from "./layout-types";
import { sizePropsToStyle, type SizeProps } from "./flutter-style";
import { POSITIONED_DISPLAY_NAME } from "./positioned";

export enum StackFit {
  /** Non-positioned children take their natural size. */
  loose = "loose",
  /**
   * Each non-positioned child is forced to fill the entire stack
   * (width & height 100%).  Achieved by wrapping in an absolute-fill div.
   */
  expand = "expand",
  /** Pass constraints through unchanged (same as loose in HTML). */
  passthrough = "passthrough",
}

export interface StackProps
  extends React.HTMLAttributes<HTMLDivElement>, SizeProps {
  /**
   * Where non-positioned children are placed inside the stack.
   * Only meaningful when fit is "loose" / "passthrough".
   * Equivalent to Flutter's Stack.alignment.
   */
  alignment?: Alignment;
  /**
   * How non-positioned children are sized relative to the stack.
   * Equivalent to Flutter's Stack.fit.
   */
  fit?: StackFit;
  /** Whether to clip children that overflow. Default "hidden". */
  clipBehavior?: "hidden" | "visible";
  key?: React.Key;
}

// Maps our Alignment enum values (which are Tailwind class strings) to
// plain CSS so we can apply them inline without needing Tailwind at runtime.
const alignToCss: Record<Alignment, React.CSSProperties> = {
  [Alignment.topLeft]: {
    alignItems: "flex-start",
    justifyContent: "flex-start",
  },
  [Alignment.topCenter]: { alignItems: "flex-start", justifyContent: "center" },
  [Alignment.topRight]: {
    alignItems: "flex-start",
    justifyContent: "flex-end",
  },
  [Alignment.centerLeft]: {
    alignItems: "center",
    justifyContent: "flex-start",
  },
  [Alignment.center]: { alignItems: "center", justifyContent: "center" },
  [Alignment.centerRight]: { alignItems: "center", justifyContent: "flex-end" },
  [Alignment.bottomLeft]: {
    alignItems: "flex-end",
    justifyContent: "flex-start",
  },
  [Alignment.bottomCenter]: {
    alignItems: "flex-end",
    justifyContent: "center",
  },
  [Alignment.bottomRight]: {
    alignItems: "flex-end",
    justifyContent: "flex-end",
  },
};

/**
 * A widget that positions its children relative to the edges of its box.
 * Non-positioned children are stacked in document order (last child on top).
 * Use <Positioned> for children that need explicit top/right/bottom/left.
 *
 * Equivalent to Flutter's Stack() widget.
 */
export const Stack = React.forwardRef<HTMLDivElement, StackProps>(
  (
    {
      alignment = Alignment.topLeft,
      fit = StackFit.loose,
      clipBehavior = "hidden",
      width,
      height,
      minWidth,
      maxWidth,
      minHeight,
      maxHeight,
      children,
      className,
      style,
      ...props
    },
    ref,
  ) => {
    return (
      <div
        ref={ref}
        className={cn(
          // Stack is a positioned container — NOT a flex container.
          // Children use absolute positioning (via <Positioned>) or natural
          // stacking (display:contents / block inside position:relative).
          "relative",
          clipBehavior === "hidden" ? "overflow-hidden" : "overflow-visible",
          className,
        )}
        style={{
          ...sizePropsToStyle({
            width,
            height,
            minWidth,
            maxWidth,
            minHeight,
            maxHeight,
          }),
          ...style,
        }}
        {...props}
      >
        {fit === StackFit.expand
          ? // Wrap each child in an absolutely-positioned fill div so it
            // stretches to fill the entire stack — no cloneElement needed.
            React.Children.map(children, (child, i) => (
              <div
                key={i}
                style={{
                  position: "absolute",
                  inset: 0,
                  display: "flex",
                  ...alignToCss[alignment],
                }}
              >
                {child}
              </div>
            ))
          : // Default (loose): children stack in normal flow inside the
            // relative container.  Each non-Positioned child sits in its
            // own layer using a flex wrapper that honours the alignment.
            React.Children.map(children, (child, i) => {
              // Skip null / undefined / boolean children
              if (
                child === null ||
                child === undefined ||
                typeof child === "boolean"
              ) {
                return child;
              }

              // Detect <Positioned> via its displayName — it manages its own placement.
              const isPositioned =
                React.isValidElement(child) &&
                (child.type as { displayName?: string }).displayName ===
                  POSITIONED_DISPLAY_NAME;

              if (isPositioned)
                return <React.Fragment key={i}>{child}</React.Fragment>;

              // Non-positioned children: wrap in an absolute fill + flex div
              // that aligns the child according to the stack's alignment.
              return (
                <div
                  key={i}
                  style={{
                    position: "absolute",
                    inset: 0,
                    display: "flex",
                    pointerEvents: "none",
                    ...alignToCss[alignment],
                  }}
                >
                  <div style={{ pointerEvents: "auto" }}>{child}</div>
                </div>
              );
            })}
      </div>
    );
  },
);

Stack.displayName = "Stack";

import React, { useState } from "react";
import { cn } from "../utils";

// ─── Types ────────────────────────────────────────────────────────────────────
export interface StepItem {
  title: string;
  subtitle?: string;
  content?: React.ReactNode;
  isCompleted?: boolean;
}

type StepState = "indexed" | "editing" | "complete" | "disabled" | "error";

interface StepperProps {
  steps: StepItem[];
  currentStep?: number;
  onStepTapped?: (index: number) => void;
  isVertical?: boolean;
  physics?: "clamped" | "scroll";
  className?: string;
}

// ─── Stepper ──────────────────────────────────────────────────────────────────
export function Stepper({
  steps,
  currentStep = 0,
  onStepTapped,
  isVertical = true,
  className,
}: StepperProps) {
  return (
    <div className={cn(isVertical ? "flex flex-col gap-0" : "flex flex-row items-start", className)}>
      {steps.map((step, i) => {
        const isDone = i < currentStep;
        const isActive = i === currentStep;
        const isLast = i === steps.length - 1;

        return (
          <div
            key={i}
            className={cn(
              isVertical ? "flex gap-4" : "flex flex-col items-center flex-1"
            )}
          >
            {/* Step indicator + line */}
            <div className={cn(isVertical ? "flex flex-col items-center" : "flex items-center w-full")}>
              {/* Circle */}
              <button
                onClick={() => onStepTapped?.(i)}
                className={cn(
                  "w-8 h-8 rounded-full flex items-center justify-center text-xs font-bold shrink-0 transition-all",
                  isDone
                    ? "bg-primary text-primary-foreground"
                    : isActive
                    ? "bg-primary text-primary-foreground ring-4 ring-primary/20"
                    : "bg-muted text-muted-foreground border border-border"
                )}
              >
                {isDone ? (
                  <svg width="14" height="14" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth={3}>
                    <path d="M5 13l4 4L19 7" strokeLinecap="round" strokeLinejoin="round" />
                  </svg>
                ) : (
                  i + 1
                )}
              </button>

              {/* Connector line */}
              {!isLast && (
                <div
                  className={cn(
                    "transition-colors duration-300",
                    isVertical ? "w-0.5 flex-1 min-h-[24px] my-1" : "h-0.5 flex-1 mx-1"
                  )}
                  style={{ backgroundColor: isDone ? "hsl(var(--primary))" : "hsl(var(--border))" }}
                />
              )}
            </div>

            {/* Step content */}
            <div className={cn(isVertical ? "flex-1 pb-4" : "pt-2 text-center px-1")}>
              <div className={cn("text-xs font-semibold", isActive ? "text-foreground" : "text-muted-foreground")}>
                {step.title}
              </div>
              {step.subtitle && (
                <div className="text-[10px] text-muted-foreground/70 mt-0.5">{step.subtitle}</div>
              )}
              {isActive && step.content && (
                <div className="mt-3 text-xs">{step.content}</div>
              )}
            </div>
          </div>
        );
      })}
    </div>
  );
}

// ─── useStepController ────────────────────────────────────────────────────────
export function useStepController(totalSteps: number, initial = 0) {
  const [currentStep, setCurrentStep] = useState(initial);
  const next = () => setCurrentStep((p) => Math.min(p + 1, totalSteps - 1));
  const previous = () => setCurrentStep((p) => Math.max(p - 1, 0));
  const goTo = (i: number) => setCurrentStep(i);
  const isFirst = currentStep === 0;
  const isLast = currentStep === totalSteps - 1;
  return { currentStep, next, previous, goTo, isFirst, isLast };
}

