/**
 * cached-network-image.ts
 * A React analog of Flutter's `cached_network_image` package.
 *
 * Features:
 *  - In-memory LRU image cache (avoids re-fetching already-loaded URLs)
 *  - Persistent sessionStorage cache (survives re-renders, not page refresh)
 *  - Loading placeholder support
 *  - Error widget / fallback support
 *  - Retry logic with exponential back-off
 *  - Progress tracking
 *  - Fade-in transition when image loads
 *  - `useNetworkImage` hook for headless usage
 *  - `CachedNetworkImage` drop-in component
 *  - `CacheManager` for manual cache control
 */

import React, { useEffect, useRef, useState, useCallback } from "react";

// ─── Cache Storage ────────────────────────────────────────────────────────────

type CacheEntry = {
  objectUrl: string;
  size: number;
  timestamp: number;
};

const MAX_MEMORY_ENTRIES = 150;
const SESSION_KEY_PREFIX = "cnimg_";

class ImageCacheManager {
  private memCache = new Map<string, CacheEntry>();
  private loading = new Map<string, Promise<CacheEntry>>();

  /** Check if URL is in memory or session cache. */
  has(url: string): boolean {
    return this.memCache.has(url) || this._hasSession(url);
  }

  /** Get cached object URL synchronously (memory only). */
  get(url: string): string | null {
    return this.memCache.get(url)?.objectUrl ?? null;
  }

  /** Evict a specific URL from all caches. */
  evict(url: string): void {
    const entry = this.memCache.get(url);
    if (entry) {
      URL.revokeObjectURL(entry.objectUrl);
      this.memCache.delete(url);
    }
    try { sessionStorage.removeItem(SESSION_KEY_PREFIX + btoa(url)); } catch { /* noop */ }
  }

  /** Clear all cached images. */
  clearAll(): void {
    this.memCache.forEach((e) => URL.revokeObjectURL(e.objectUrl));
    this.memCache.clear();
    // Clear session entries
    try {
      Object.keys(sessionStorage)
        .filter((k) => k.startsWith(SESSION_KEY_PREFIX))
        .forEach((k) => sessionStorage.removeItem(k));
    } catch { /* noop */ }
  }

  /** Fetch and cache an image URL. Returns a cached ObjectURL. */
  async fetch(
    url: string,
    onProgress?: (progress: number) => void,
    retries = 3,
  ): Promise<string> {
    // 1. In-memory hit
    const mem = this.memCache.get(url);
    if (mem) return mem.objectUrl;

    // 2. Deduplicate concurrent requests
    const inflight = this.loading.get(url);
    if (inflight) return (await inflight).objectUrl;

    // 3. Session hit — restore from base64
    const session = this._getSession(url);
    if (session) {
      const objectUrl = session;
      this._addToMemory(url, { objectUrl, size: 0, timestamp: Date.now() });
      return objectUrl;
    }

    // 4. Network fetch with retry
    const promise = this._fetchWithRetry(url, onProgress, retries);
    this.loading.set(url, promise);
    try {
      const entry = await promise;
      this._addToMemory(url, entry);
      this._setSession(url, entry.objectUrl);
      return entry.objectUrl;
    } finally {
      this.loading.delete(url);
    }
  }

  private async _fetchWithRetry(
    url: string,
    onProgress?: (p: number) => void,
    retriesLeft = 3,
  ): Promise<CacheEntry> {
    for (let attempt = 0; attempt < retriesLeft; attempt++) {
      try {
        const res = await fetch(url);
        if (!res.ok) throw new Error(`HTTP ${res.status}`);

        const contentLength = res.headers.get("content-length");
        const total = contentLength ? parseInt(contentLength, 10) : 0;
        let received = 0;

        if (onProgress && res.body) {
          const reader = res.body.getReader();
          const chunks: Uint8Array[] = [];
          while (true) {
            const { done, value } = await reader.read();
            if (done) break;
            chunks.push(value);
            received += value.length;
            if (total > 0) onProgress(received / total);
          }
          const blob = new Blob(chunks as any);
          return { objectUrl: URL.createObjectURL(blob), size: blob.size, timestamp: Date.now() };
        }

        const blob = await res.blob();
        onProgress?.(1);
        return { objectUrl: URL.createObjectURL(blob), size: blob.size, timestamp: Date.now() };
      } catch (e) {
        if (attempt === retriesLeft - 1) throw e;
        await new Promise((r) => setTimeout(r, 300 * 2 ** attempt));
      }
    }
    throw new Error("Max retries exceeded");
  }

  private _addToMemory(url: string, entry: CacheEntry): void {
    if (this.memCache.size >= MAX_MEMORY_ENTRIES) {
      // Evict oldest
      const oldest = [...this.memCache.entries()].sort((a, b) => a[1].timestamp - b[1].timestamp)[0];
      if (oldest) {
        URL.revokeObjectURL(oldest[1].objectUrl);
        this.memCache.delete(oldest[0]);
      }
    }
    this.memCache.set(url, entry);
  }

  private _hasSession(url: string): boolean {
    try { return !!sessionStorage.getItem(SESSION_KEY_PREFIX + btoa(url)); } catch { return false; }
  }

  private _getSession(url: string): string | null {
    try { return sessionStorage.getItem(SESSION_KEY_PREFIX + btoa(url)); } catch { return null; }
  }

  private _setSession(url: string, objectUrl: string): void {
    try { sessionStorage.setItem(SESSION_KEY_PREFIX + btoa(url), objectUrl); } catch { /* quota exceeded */ }
  }
}

/** Singleton cache manager — equivalent to Flutter's DefaultCacheManager. */
export const CacheManager = new ImageCacheManager();

// ─── useNetworkImage hook ─────────────────────────────────────────────────────

export type NetworkImageStatus = "idle" | "loading" | "loaded" | "error";

export interface UseNetworkImageResult {
  src: string | null;
  status: NetworkImageStatus;
  progress: number;
  error: Error | null;
  reload: () => void;
}

export interface UseNetworkImageOptions {
  /** Number of retry attempts on failure. Default 3. */
  retries?: number;
  /** Delay in ms before the first load attempt (useful for priority queuing). */
  delay?: number;
  /** Skip the cache and always re-fetch. */
  forceRefresh?: boolean;
  /** Custom cache manager instance. */
  cacheManager?: ImageCacheManager;
}

/**
 * React hook that fetches and caches a network image.
 * Equivalent to flutter's `CachedNetworkImage` state.
 */
export function useNetworkImage(
  url: string | null | undefined,
  options: UseNetworkImageOptions = {},
): UseNetworkImageResult {
  const {
    retries = 3,
    delay = 0,
    forceRefresh = false,
    cacheManager = CacheManager,
  } = options;

  const [status, setStatus] = useState<NetworkImageStatus>(() =>
    url && !forceRefresh && cacheManager.has(url) ? "loaded" : url ? "loading" : "idle",
  );
  const [src, setSrc] = useState<string | null>(() =>
    url && !forceRefresh ? cacheManager.get(url) : null,
  );
  const [progress, setProgress] = useState(0);
  const [error, setError] = useState<Error | null>(null);
  const [reloadKey, setReloadKey] = useState(0);

  const reload = useCallback(() => {
    if (url) {
      cacheManager.evict(url);
      setReloadKey((k) => k + 1);
      setSrc(null);
      setStatus("loading");
      setError(null);
      setProgress(0);
    }
  }, [url, cacheManager]);

  useEffect(() => {
    if (!url) { setStatus("idle"); return; }

    if (!forceRefresh && cacheManager.has(url)) {
      setSrc(cacheManager.get(url));
      setStatus("loaded");
      return;
    }

    let cancelled = false;
    setStatus("loading");

    const run = async () => {
      if (delay > 0) await new Promise((r) => setTimeout(r, delay));
      if (cancelled) return;
      try {
        const objectUrl = await cacheManager.fetch(
          url,
          (p) => { if (!cancelled) setProgress(p); },
          retries,
        );
        if (!cancelled) { setSrc(objectUrl); setStatus("loaded"); }
      } catch (e) {
        if (!cancelled) { setError(e as Error); setStatus("error"); }
      }
    };

    run();
    return () => { cancelled = true; };
  }, [url, reloadKey, retries, delay, forceRefresh, cacheManager]);

  return { src, status, progress, error, reload };
}

// ─── CachedNetworkImage Component ─────────────────────────────────────────────

export interface CachedNetworkImageProps extends Omit<React.ImgHTMLAttributes<HTMLImageElement>, "src"> {
  /** The remote image URL. */
  imageUrl: string;
  /**
   * Widget shown while loading.
   * Receives a `progress` value (0–1) when Content-Length is available.
   */
  placeholder?: (progress: number) => React.ReactNode;
  /**
   * Widget shown when the image fails to load.
   * Receives the error and a `reload` callback.
   */
  errorWidget?: (error: Error, reload: () => void) => React.ReactNode;
  /** Fade-in duration in ms. Default 300. */
  fadeInDuration?: number;
  /** Fade-in curve: just maps to CSS easing. Default "ease-out". */
  fadeInCurve?: string;
  /** Whether to show a progress indicator. Default false. */
  useOldImageOnUrlChange?: boolean;
  /** Object-fit for the image. Default "cover". */
  fit?: React.CSSProperties["objectFit"];
  /** Hook options forwarded to useNetworkImage. */
  cacheOptions?: UseNetworkImageOptions;
  /** Container className wrapping the image + placeholder. */
  containerClassName?: string;
  /** Container style. */
  containerStyle?: React.CSSProperties;
}

/**
 * A drop-in component that fetches, caches, and displays a network image
 * with loading/error states and a fade-in transition.
 *
 * Equivalent to Flutter's `CachedNetworkImage()` widget.
 *
 * ```tsx
 * <CachedNetworkImage
 *   imageUrl="https://example.com/photo.jpg"
 *   placeholder={(p) => <SkeletonBox />}
 *   errorWidget={(err, reload) => <button onClick={reload}>Retry</button>}
 *   fit="cover"
 *   width={300}
 *   height={200}
 * />
 * ```
 */
export const CachedNetworkImage = React.forwardRef<HTMLDivElement, CachedNetworkImageProps>(
  (
    {
      imageUrl,
      placeholder,
      errorWidget,
      fadeInDuration = 300,
      fadeInCurve = "ease-out",
      fit = "cover",
      cacheOptions,
      containerClassName,
      containerStyle,
      className,
      style,
      alt,
      width,
      height,
      ...imgProps
    },
    ref,
  ) => {
    const { src, status, progress, error, reload } = useNetworkImage(imageUrl, cacheOptions);

    return (
      <div
        ref={ref}
        className={containerClassName}
        style={{ position: "relative", overflow: "hidden", ...containerStyle }}
      >
        {/* Placeholder layer */}
        {status !== "loaded" && status !== "error" && (
          <div
            style={{ position: "absolute", inset: 0, display: "flex", alignItems: "center", justifyContent: "center" }}
          >
            {placeholder ? placeholder(progress) : (
              <div
                className="w-full h-full animate-pulse"
                style={{ backgroundColor: "hsl(var(--muted))" }}
              />
            )}
          </div>
        )}

        {/* Error layer */}
        {status === "error" && error && (
          <div
            style={{ position: "absolute", inset: 0, display: "flex", alignItems: "center", justifyContent: "center" }}
          >
            {errorWidget ? errorWidget(error, reload) : (
              <div style={{ textAlign: "center", color: "hsl(var(--muted-foreground))", fontSize: 12 }}>
                <div style={{ fontSize: 24, marginBottom: 4 }}>⚠️</div>
                <button onClick={reload} style={{ textDecoration: "underline", cursor: "pointer", background: "none", border: "none", color: "inherit" }}>
                  Retry
                </button>
              </div>
            )}
          </div>
        )}

        {/* Image layer */}
        {src && (
          <img
            src={src}
            alt={alt ?? ""}
            className={className}
            style={{
              display: "block",
              width: typeof width === "number" ? `${width}px` : width ?? "100%",
              height: typeof height === "number" ? `${height}px` : height ?? "100%",
              objectFit: fit,
              opacity: status === "loaded" ? 1 : 0,
              transition: `opacity ${fadeInDuration}ms ${fadeInCurve}`,
              ...style,
            }}
            {...imgProps}
          />
        )}
      </div>
    );
  },
);

CachedNetworkImage.displayName = "CachedNetworkImage";

/**
 * connectivity.ts — Flutter `connectivity_plus` package equivalent for React
 * Mirrors: Connectivity, ConnectivityResult, onConnectivityChanged
 */

// ─── ConnectivityResult ───────────────────────────────────────────────────────
export enum ConnectivityResult {
  wifi = "wifi",
  mobile = "mobile",
  ethernet = "ethernet",
  bluetooth = "bluetooth",
  vpn = "vpn",
  other = "other",
  none = "none",
}

// ─── Connectivity ─────────────────────────────────────────────────────────────
export class Connectivity {
  private static listeners = new Set<(result: ConnectivityResult) => void>();
  private static unlistenCallbacks: (() => void)[] = [];

  /**
   * Get current connectivity result.
   * Uses Navigator.connection API when available.
   */
  static async checkConnectivity(): Promise<ConnectivityResult> {
    if (!navigator.onLine) return ConnectivityResult.none;

    const conn = (navigator as any).connection;
    if (!conn) return ConnectivityResult.wifi; // assume wifi if API unavailable

    const type = conn.type as string;
    if (type === "wifi") return ConnectivityResult.wifi;
    if (type === "ethernet") return ConnectivityResult.ethernet;
    if (type === "bluetooth") return ConnectivityResult.bluetooth;
    if (type === "cellular" || type === "wimax") return ConnectivityResult.mobile;
    if (type === "vpn") return ConnectivityResult.vpn;
    if (type === "none" || !navigator.onLine) return ConnectivityResult.none;
    return ConnectivityResult.other;
  }

  /**
   * Subscribe to connectivity changes.
   * Returns an unsubscribe function.
   */
  static onConnectivityChanged(callback: (result: ConnectivityResult) => void): () => void {
    const onOnline = () => callback(ConnectivityResult.wifi);
    const onOffline = () => callback(ConnectivityResult.none);

    window.addEventListener("online", onOnline);
    window.addEventListener("offline", onOffline);

    return () => {
      window.removeEventListener("online", onOnline);
      window.removeEventListener("offline", onOffline);
    };
  }

  static isOnline(): boolean {
    return navigator.onLine;
  }

  static isOffline(): boolean {
    return !navigator.onLine;
  }

  /** Get effective connection type */
  static getEffectiveType(): string {
    const conn = (navigator as any).connection;
    return conn?.effectiveType ?? "unknown";
  }

  /** Get estimated downlink bandwidth in Mbps */
  static getDownlink(): number {
    const conn = (navigator as any).connection;
    return conn?.downlink ?? -1;
  }

  /** Get round-trip time estimate */
  static getRtt(): number {
    const conn = (navigator as any).connection;
    return conn?.rtt ?? -1;
  }
}

// ─── useConnectivity React hook ───────────────────────────────────────────────
import { useState, useEffect } from "react";

export function useConnectivity(): {
  isOnline: boolean;
  connectivityResult: ConnectivityResult;
  effectiveType: string;
} {
  const [isOnline, setIsOnline] = useState(navigator.onLine);
  const [result, setResult] = useState<ConnectivityResult>(
    navigator.onLine ? ConnectivityResult.wifi : ConnectivityResult.none
  );

  useEffect(() => {
    const check = async () => {
      const r = await Connectivity.checkConnectivity();
      setResult(r);
    };

    check();
    const unsub = Connectivity.onConnectivityChanged((r) => {
      setIsOnline(r !== ConnectivityResult.none);
      setResult(r);
    });

    return unsub;
  }, []);

  return { isOnline, connectivityResult: result, effectiveType: Connectivity.getEffectiveType() };
}

/**
 * currency-format.ts — Currency formatting utilities
 * Inspired by Flutter's NumberFormat.currency and intl package
 */

// ─── Currency symbols map ─────────────────────────────────────────────────────
export const CURRENCY_SYMBOLS: Record<string, string> = {
  USD: "$", EUR: "€", GBP: "£", JPY: "¥", CNY: "¥",
  KES: "KSh", NGN: "₦", GHS: "₵", ZAR: "R", EGP: "£",
  INR: "₹", BRL: "R$", AUD: "A$", CAD: "C$", CHF: "Fr",
  MXN: "MX$", SEK: "kr", NOK: "kr", DKK: "kr", PLN: "zł",
  RUB: "₽", TRY: "₺", AED: "د.إ", SAR: "﷼", THB: "฿",
  PHP: "₱", IDR: "Rp", MYR: "RM", VND: "₫", TWD: "NT$",
  HKD: "HK$", SGD: "S$", NZD: "NZ$", CZK: "Kč", HUF: "Ft",
  ILS: "₪", CLP: "$", COP: "$", PEN: "S/", UYU: "$",
  KRW: "₩", PKR: "₨", BDT: "৳", LKR: "₨", MMK: "K",
};

// ─── formatCurrency ───────────────────────────────────────────────────────────
export interface CurrencyFormatOptions {
  currencyCode?: string;
  locale?: string;
  decimalDigits?: number;
  symbol?: string;
  symbolPlacement?: "before" | "after";
  thousandsSeparator?: string;
  decimalSeparator?: string;
  compact?: boolean;
  showSymbol?: boolean;
}

export function formatCurrency(
  amount: number,
  options: CurrencyFormatOptions = {}
): string {
  const {
    currencyCode = "USD",
    locale = "en",
    decimalDigits = 2,
    symbol,
    compact = false,
    showSymbol = true,
  } = options;

  const sym = symbol ?? CURRENCY_SYMBOLS[currencyCode] ?? currencyCode;

  try {
    const formatted = new Intl.NumberFormat(locale, {
      style: "currency",
      currency: currencyCode,
      minimumFractionDigits: decimalDigits,
      maximumFractionDigits: decimalDigits,
      notation: compact ? "compact" : "standard",
    } as Intl.NumberFormatOptions).format(amount);

    if (!showSymbol) {
      return formatted.replace(/[^0-9.,\s]/g, "").trim();
    }

    return formatted;
  } catch {
    // Fallback
    const abs = Math.abs(amount);
    const fixed = abs.toFixed(decimalDigits);
    const [int, dec] = fixed.split(".");
    const intFormatted = int.replace(/\B(?=(\d{3})+(?!\d))/g, ",");
    const result = dec ? `${intFormatted}.${dec}` : intFormatted;
    const signed = amount < 0 ? `-${sym}${result}` : `${sym}${result}`;
    return signed;
  }
}

// ─── parseCurrency ────────────────────────────────────────────────────────────
export function parseCurrency(input: string): number {
  const cleaned = input.replace(/[^0-9.-]/g, "");
  return parseFloat(cleaned) || 0;
}

// ─── formatCompact ────────────────────────────────────────────────────────────
export function formatCompact(amount: number, locale = "en"): string {
  return new Intl.NumberFormat(locale, { notation: "compact" } as Intl.NumberFormatOptions).format(amount);
}

// ─── formatCurrencyCompact ────────────────────────────────────────────────────
export function formatCurrencyCompact(amount: number, currencyCode = "USD", locale = "en"): string {
  return formatCurrency(amount, { currencyCode, locale, compact: true });
}

// ─── Accounting-style formatting ──────────────────────────────────────────────
export function formatAccounting(amount: number, currencyCode = "USD", locale = "en"): string {
  if (amount < 0) {
    return `(${formatCurrency(Math.abs(amount), { currencyCode, locale })})`;
  }
  return formatCurrency(amount, { currencyCode, locale });
}

// ─── CurrencyFormatter class ──────────────────────────────────────────────────
export class CurrencyFormatter {
  private options: CurrencyFormatOptions;

  constructor(options: CurrencyFormatOptions = {}) {
    this.options = options;
  }

  format(amount: number): string {
    return formatCurrency(amount, this.options);
  }

  parse(input: string): number {
    return parseCurrency(input);
  }

  withCurrency(currencyCode: string): CurrencyFormatter {
    return new CurrencyFormatter({ ...this.options, currencyCode });
  }

  withLocale(locale: string): CurrencyFormatter {
    return new CurrencyFormatter({ ...this.options, locale });
  }

  withDecimals(decimalDigits: number): CurrencyFormatter {
    return new CurrencyFormatter({ ...this.options, decimalDigits });
  }

  static usd(locale = "en") { return new CurrencyFormatter({ currencyCode: "USD", locale }); }
  static eur(locale = "de") { return new CurrencyFormatter({ currencyCode: "EUR", locale }); }
  static gbp(locale = "en-GB") { return new CurrencyFormatter({ currencyCode: "GBP", locale }); }
  static jpy(locale = "ja") { return new CurrencyFormatter({ currencyCode: "JPY", locale, decimalDigits: 0 }); }
  static kes(locale = "sw") { return new CurrencyFormatter({ currencyCode: "KES", locale }); }
  static ngn(locale = "en-NG") { return new CurrencyFormatter({ currencyCode: "NGN", locale }); }
  static inr(locale = "hi") { return new CurrencyFormatter({ currencyCode: "INR", locale }); }
}

export const formatDate = (dateInput?: string | Date) => {
  if (!dateInput) return "";
  const date =
    typeof dateInput === "string"
      ? new Date(dateInput.replace(" ", "T") + "Z")
      : dateInput;

  const now = new Date();
  const diffInHours = (now.getTime() - date.getTime()) / (1000 * 60 * 60);

  if (diffInHours > 24) {
    return date.toLocaleDateString(undefined, {
      month: "short",
      day: "numeric",
    });
  }
  return date.toLocaleTimeString(undefined, {
    hour: "2-digit",
    minute: "2-digit",
  });
};

/**
 * device-info.ts — Flutter `device_info_plus` package equivalent for React
 * Mirrors: WebBrowserInfo, DeviceInfoPlugin, platform detection
 */

// ─── Types ────────────────────────────────────────────────────────────────────
export type PlatformType = "windows" | "macos" | "linux" | "android" | "ios" | "chromeos" | "unknown";
export type BrowserType = "chrome" | "firefox" | "safari" | "edge" | "opera" | "brave" | "unknown";
export type DeviceType = "mobile" | "tablet" | "desktop";

export interface WebBrowserInfo {
  browserName: BrowserType;
  appCodeName: string;
  appName: string;
  appVersion: string;
  deviceMemory: number | null;
  language: string;
  languages: string[];
  platform: PlatformType;
  product: string;
  productSub: string;
  userAgent: string;
  vendor: string;
  devicePixelRatio: number;
  hardwareConcurrency: number;
  maxTouchPoints: number;
  isOnline: boolean;
  cookiesEnabled: boolean;
  screenWidth: number;
  screenHeight: number;
  windowWidth: number;
  windowHeight: number;
  colorDepth: number;
  deviceType: DeviceType;
  isStandalone: boolean;
  isMobile: boolean;
  isTablet: boolean;
  isDesktop: boolean;
}

// ─── DeviceInfoPlugin ─────────────────────────────────────────────────────────
export class DeviceInfoPlugin {
  static async webBrowserInfo(): Promise<WebBrowserInfo> {
    const ua = navigator.userAgent;
    const vendor = navigator.vendor ?? "";

    const browserName = (() => {
      if (/brave/i.test(ua) || (navigator as any).brave) return "brave";
      if (/edg/i.test(ua)) return "edge";
      if (/opr|opera/i.test(ua)) return "opera";
      if (/firefox/i.test(ua)) return "firefox";
      if (/safari/i.test(ua) && !/chrome/i.test(ua)) return "safari";
      if (/chrome/i.test(ua)) return "chrome";
      return "unknown";
    })() as BrowserType;

    const platform = (() => {
      const p = navigator.platform.toLowerCase();
      if (/android/i.test(ua)) return "android";
      if (/iphone|ipad|ipod/i.test(ua)) return "ios";
      if (/win/i.test(p)) return "windows";
      if (/mac/i.test(p)) return "macos";
      if (/linux/i.test(p)) return "linux";
      if (/cros/i.test(ua)) return "chromeos";
      return "unknown";
    })() as PlatformType;

    const isMobile = /android|webos|iphone|ipod|blackberry|iemobile|opera mini/i.test(ua);
    const isTablet = /ipad|android(?!.*mobile)/i.test(ua) || (window.innerWidth >= 600 && window.innerWidth <= 1024);
    const isDesktop = !isMobile && !isTablet;

    const deviceType: DeviceType = isMobile ? "mobile" : isTablet ? "tablet" : "desktop";

    return {
      browserName,
      appCodeName: navigator.appCodeName,
      appName: navigator.appName,
      appVersion: navigator.appVersion,
      deviceMemory: (navigator as any).deviceMemory ?? null,
      language: navigator.language,
      languages: Array.from(navigator.languages),
      platform,
      product: navigator.product,
      productSub: (navigator as any).productSub ?? "",
      userAgent: ua,
      vendor,
      devicePixelRatio: window.devicePixelRatio,
      hardwareConcurrency: navigator.hardwareConcurrency,
      maxTouchPoints: navigator.maxTouchPoints,
      isOnline: navigator.onLine,
      cookiesEnabled: navigator.cookieEnabled,
      screenWidth: screen.width,
      screenHeight: screen.height,
      windowWidth: window.innerWidth,
      windowHeight: window.innerHeight,
      colorDepth: screen.colorDepth,
      deviceType,
      isStandalone: (window.matchMedia("(display-mode: standalone)").matches),
      isMobile,
      isTablet,
      isDesktop,
    };
  }

  static getPlatform(): PlatformType {
    const ua = navigator.userAgent;
    const p = navigator.platform.toLowerCase();
    if (/android/i.test(ua)) return "android";
    if (/iphone|ipad|ipod/i.test(ua)) return "ios";
    if (/win/i.test(p)) return "windows";
    if (/mac/i.test(p)) return "macos";
    if (/linux/i.test(p)) return "linux";
    if (/cros/i.test(ua)) return "chromeos";
    return "unknown";
  }

  static isAndroid(): boolean { return DeviceInfoPlugin.getPlatform() === "android"; }
  static isIOS(): boolean { return DeviceInfoPlugin.getPlatform() === "ios"; }
  static isWindows(): boolean { return DeviceInfoPlugin.getPlatform() === "windows"; }
  static isMacOS(): boolean { return DeviceInfoPlugin.getPlatform() === "macos"; }
  static isLinux(): boolean { return DeviceInfoPlugin.getPlatform() === "linux"; }
  static isWeb(): boolean { return typeof window !== "undefined"; }
  static isDarkMode(): boolean { return window.matchMedia("(prefers-color-scheme: dark)").matches; }
  static prefersReducedMotion(): boolean { return window.matchMedia("(prefers-reduced-motion: reduce)").matches; }
}

// ─── useDeviceInfo hook ───────────────────────────────────────────────────────
import { useState, useEffect } from "react";

export function useDeviceInfo(): { info: WebBrowserInfo | null; isLoading: boolean } {
  const [info, setInfo] = useState<WebBrowserInfo | null>(null);
  const [isLoading, setIsLoading] = useState(true);

  useEffect(() => {
    DeviceInfoPlugin.webBrowserInfo().then((i) => {
      setInfo(i);
      setIsLoading(false);
    });
  }, []);

  return { info, isLoading };
}

// ─── Platform convenience ─────────────────────────────────────────────────────
export const Platform = {
  isAndroid: DeviceInfoPlugin.isAndroid(),
  isIOS: DeviceInfoPlugin.isIOS(),
  isWindows: DeviceInfoPlugin.isWindows(),
  isMacOS: DeviceInfoPlugin.isMacOS(),
  isLinux: DeviceInfoPlugin.isLinux(),
  isWeb: DeviceInfoPlugin.isWeb(),
  operatingSystem: DeviceInfoPlugin.getPlatform(),
};

/**
 * flutter-animate.ts — Flutter `flutter_animate` package equivalent for React
 * CSS animation preset builders and chainable animation helpers.
 */

// ─── Types ────────────────────────────────────────────────────────────────────
export interface AnimationPreset {
  keyframes?: Keyframe[];
  options?: KeyframeAnimationOptions;
