// ─── Curves (easing functions) ────────────────────────────────────────────────
export const Curves = {
  linear: "linear",
  ease: "ease",
  easeIn: "ease-in",
  easeOut: "ease-out",
  easeInOut: "ease-in-out",
  bounceIn: "cubic-bezier(0.215, 0.61, 0.355, 1)",
  bounceOut: "cubic-bezier(0.34, 1.56, 0.64, 1)",
  elasticIn: "cubic-bezier(0.36, 0.07, 0.19, 0.97)",
  elasticOut: "cubic-bezier(0.64, 0.57, 0.67, 1.53)",
  decelerate: "cubic-bezier(0, 0, 0.2, 1)",
  accelerate: "cubic-bezier(0.4, 0, 1, 1)",
  fastOutSlowIn: "cubic-bezier(0.4, 0, 0.2, 1)",
  slowMiddle: "cubic-bezier(0.15, 0.85, 0.15, 0.85)",
  anticipate: "cubic-bezier(0.36, 0, 0.66, -0.56)",
};

// ─── CSS class-based animation presets ────────────────────────────────────────
export const AnimatePresets = {
  fadeIn: "animate-in fade-in",
  fadeOut: "animate-out fade-out",
  slideInFromBottom: "animate-in slide-in-from-bottom",
  slideInFromTop: "animate-in slide-in-from-top",
  slideInFromLeft: "animate-in slide-in-from-left",
  slideInFromRight: "animate-in slide-in-from-right",
  zoomIn: "animate-in zoom-in",
  zoomOut: "animate-out zoom-out",
  spinIn: "animate-in spin-in",
};

// ─── Flutter-style animation chain builder ────────────────────────────────────
interface AnimationStep {
  type: "fade" | "scale" | "slide" | "rotate" | "blur" | "shake" | "shimmer";
  from?: number;
  to?: number;
  duration?: number;
  delay?: number;
  curve?: string;
  begin?: number;
  end?: number;
  offset?: { x?: number; y?: number };
}

export class Animate {
  private steps: AnimationStep[] = [];
  private _delay = 0;
  private _duration = 300;
  private _curve = Curves.easeInOut;

  static effect() { return new Animate(); }

  delay(ms: number) { this._delay = ms; return this; }
  duration(ms: number) { this._duration = ms; return this; }
  curve(c: string) { this._curve = c; return this; }

  fadeIn(from = 0, to = 1) {
    this.steps.push({ type: "fade", from, to });
    return this;
  }

  fadeOut(from = 1, to = 0) {
    this.steps.push({ type: "fade", from, to });
    return this;
  }

  scale(begin = 0, end = 1) {
    this.steps.push({ type: "scale", begin, end });
    return this;
  }

  slideX(begin = -1, end = 0) {
    this.steps.push({ type: "slide", offset: { x: begin }, end });
    return this;
  }

  slideY(begin = -1, end = 0) {
    this.steps.push({ type: "slide", offset: { y: begin }, end });
    return this;
  }

  rotate(begin = 0, end = 1) {
    this.steps.push({ type: "rotate", begin, end });
    return this;
  }

  shake() {
    this.steps.push({ type: "shake" });
    return this;
  }

  shimmer() {
    this.steps.push({ type: "shimmer" });
    return this;
  }

  /** Build CSS animation string */
  build(): React.CSSProperties {
    const transitions: string[] = [];
    const style: React.CSSProperties = {
      animationDelay: `${this._delay}ms`,
      animationDuration: `${this._duration}ms`,
      animationTimingFunction: this._curve,
      animationFillMode: "both",
    };

    return style;
  }

  /** Get CSS class string for tailwind animate plugin */
  toCssClass(): string {
    return ["animate-in", ...this.steps.map((s) => {
      if (s.type === "fade") return "fade-in";
      if (s.type === "scale") return "zoom-in";
      if (s.type === "slide" && s.offset?.y) return "slide-in-from-bottom";
      if (s.type === "slide" && s.offset?.x) return "slide-in-from-left";
      return "";
    })].join(" ");
  }
}

// ─── useAnimation hook ────────────────────────────────────────────────────────
import { useState, useEffect, useRef } from "react";

export function useAnimation(
  trigger: boolean,
  duration = 300,
  delay = 0
): { isAnimating: boolean; style: React.CSSProperties } {
  const [isAnimating, setIsAnimating] = useState(false);

  useEffect(() => {
    if (trigger) {
      const t = setTimeout(() => setIsAnimating(true), delay);
      return () => clearTimeout(t);
    } else {
      setIsAnimating(false);
    }
  }, [trigger, delay]);

  return {
    isAnimating,
    style: {
      opacity: isAnimating ? 1 : 0,
      transition: `all ${duration}ms ${Curves.fastOutSlowIn}`,
    },
  };
}

// ─── Spring animation helper ──────────────────────────────────────────────────
export function springAnimation(options: {
  mass?: number;
  stiffness?: number;
  damping?: number;
}) {
  const { mass = 1, stiffness = 300, damping = 30 } = options;
  const frequency = Math.sqrt(stiffness / mass);
  const ratio = damping / (2 * Math.sqrt(stiffness * mass));
  // Approximate spring as a CSS bezier
  return ratio < 1
    ? Curves.bounceOut
    : Curves.fastOutSlowIn;
}

import React from "react";

/**
 * intl.ts — Flutter `intl` package equivalent for React
 * Mirrors: DateFormat, NumberFormat, Intl.PluralRules
 */

// ─── DateFormat ───────────────────────────────────────────────────────────────
export class DateFormat {
  private formatStr: string;
  private locale: string;

  constructor(formatStr: string, locale: string = "en") {
    this.formatStr = formatStr;
    this.locale = locale;
  }

  format(date: Date): string {
    const pad = (n: number, len = 2) => String(n).padStart(len, "0");
    const d = date;

    const MONTHS_FULL = ["January","February","March","April","May","June","July","August","September","October","November","December"];
    const MONTHS_SHORT = ["Jan","Feb","Mar","Apr","May","Jun","Jul","Aug","Sep","Oct","Nov","Dec"];
    const WEEKDAYS_FULL = ["Sunday","Monday","Tuesday","Wednesday","Thursday","Friday","Saturday"];
    const WEEKDAYS_SHORT = ["Sun","Mon","Tue","Wed","Thu","Fri","Sat"];

    const hours24 = d.getHours();
    const hours12 = hours24 % 12 || 12;
    const ampm = hours24 < 12 ? "AM" : "PM";

    return this.formatStr
      .replace("MMMM", MONTHS_FULL[d.getMonth()])
      .replace("MMM", MONTHS_SHORT[d.getMonth()])
      .replace("MM", pad(d.getMonth() + 1))
      .replace("M", String(d.getMonth() + 1))
      .replace("EEEE", WEEKDAYS_FULL[d.getDay()])
      .replace("EEE", WEEKDAYS_SHORT[d.getDay()])
      .replace("yyyy", String(d.getFullYear()))
      .replace("yy", String(d.getFullYear()).slice(-2))
      .replace("dd", pad(d.getDate()))
      .replace("d", String(d.getDate()))
      .replace("HH", pad(hours24))
      .replace("H", String(hours24))
      .replace("hh", pad(hours12))
      .replace("h", String(hours12))
      .replace("mm", pad(d.getMinutes()))
      .replace("ss", pad(d.getSeconds()))
      .replace("a", ampm)
      .replace("S", pad(d.getMilliseconds(), 3));
  }

  parse(input: string): Date {
    return new Date(input);
  }

  // Common preset factories
  static yMd(locale?: string) { return new DateFormat("M/d/yyyy", locale); }
  static yMMMd(locale?: string) { return new DateFormat("MMM d, yyyy", locale); }
  static yMMMMd(locale?: string) { return new DateFormat("MMMM d, yyyy", locale); }
  static yMMMEd(locale?: string) { return new DateFormat("EEE, MMM d, yyyy", locale); }
  static jm(locale?: string) { return new DateFormat("h:mm a", locale); }
  static Hm(locale?: string) { return new DateFormat("HH:mm", locale); }
  static jms(locale?: string) { return new DateFormat("h:mm:ss a", locale); }
  static MMMd(locale?: string) { return new DateFormat("MMM d", locale); }
  static EEEE(locale?: string) { return new DateFormat("EEEE", locale); }
  static LLLL(locale?: string) { return new DateFormat("MMMM", locale); }
}

// ─── NumberFormat ─────────────────────────────────────────────────────────────
export class NumberFormat {
  private options: Intl.NumberFormatOptions;
  private locale: string;
  private _prefix: string;
  private _suffix: string;

  constructor(options: Intl.NumberFormatOptions = {}, locale = "en", prefix = "", suffix = "") {
    this.options = options;
    this.locale = locale;
    this._prefix = prefix;
    this._suffix = suffix;
  }

  format(value: number): string {
    return this._prefix + new Intl.NumberFormat(this.locale, this.options).format(value) + this._suffix;
  }

  parse(input: string): number {
    return parseFloat(input.replace(/[^0-9.-]/g, ""));
  }

  // Preset factories
  static currency(symbol: string, locale = "en", decimalDigits = 2): NumberFormat {
    return new NumberFormat({
      style: "currency",
      currency: symbol,
      minimumFractionDigits: decimalDigits,
      maximumFractionDigits: decimalDigits,
    }, locale);
  }

  static decimalPattern(locale = "en"): NumberFormat {
    return new NumberFormat({ style: "decimal" }, locale);
  }

  static percentPattern(locale = "en"): NumberFormat {
    return new NumberFormat({ style: "percent", maximumFractionDigits: 1 }, locale);
  }

  static compact(locale = "en"): NumberFormat {
    return new NumberFormat({ notation: "compact" } as Intl.NumberFormatOptions, locale);
  }

  static compactCurrency(symbol: string, locale = "en"): NumberFormat {
    return new NumberFormat({
      style: "currency",
      currency: symbol,
      notation: "compact",
    } as Intl.NumberFormatOptions, locale);
  }

  static simpleCurrency(symbol: string, locale = "en", decimalDigits = 2): NumberFormat {
    return new NumberFormat({
      minimumFractionDigits: decimalDigits,
      maximumFractionDigits: decimalDigits,
    }, locale, symbol);
  }
}

// ─── Intl helpers (pluralization, etc.) ──────────────────────────────────────
export function plural(
  count: number,
  { zero, one, two, few, many, other }: {
    zero?: string; one?: string; two?: string;
    few?: string; many?: string; other: string;
  },
  locale = "en"
): string {
  const pr = new Intl.PluralRules(locale);
  const rule = pr.select(count);
  if (count === 0 && zero) return zero.replace("#", String(count));
  if (rule === "one" && one) return one.replace("#", String(count));
  if (rule === "two" && two) return two.replace("#", String(count));
  if (rule === "few" && few) return few.replace("#", String(count));
  if (rule === "many" && many) return many.replace("#", String(count));
  return other.replace("#", String(count));
}

export function select<K extends string>(
  value: K,
  options: Partial<Record<K, string>> & { other: string }
): string {
  return (options[value] ?? options.other);
}

// ─── RelativeTimeFormat ───────────────────────────────────────────────────────
export function timeAgo(date: Date, locale = "en"): string {
  const rtf = new Intl.RelativeTimeFormat(locale, { numeric: "auto" });
  const now = Date.now();
  const diff = date.getTime() - now;
  const seconds = Math.round(diff / 1000);
  const minutes = Math.round(seconds / 60);
  const hours = Math.round(minutes / 60);
  const days = Math.round(hours / 24);

  if (Math.abs(seconds) < 60) return rtf.format(seconds, "second");
  if (Math.abs(minutes) < 60) return rtf.format(minutes, "minute");
  if (Math.abs(hours) < 24) return rtf.format(hours, "hour");
  return rtf.format(days, "day");
}

/**
 * path-provider.ts — Flutter `path_provider` package equivalent for React
 * Mirrors: getApplicationDocumentsDirectory, getTemporaryDirectory, getDownloadsDirectory, etc.
 * Uses IndexedDB for binary blobs and localStorage for metadata (web equivalent).
 */

// ─── Types ────────────────────────────────────────────────────────────────────
export interface Directory {
  path: string;
  exists: () => boolean;
  create: (options?: { recursive?: boolean }) => Promise<Directory>;
  list: () => Promise<FileEntry[]>;
  delete: (options?: { recursive?: boolean }) => Promise<void>;
}

export interface FileEntry {
  name: string;
  path: string;
  size?: number;
  type?: string;
  lastModified?: number;
}

// ─── In-memory virtual file system ───────────────────────────────────────────
const VFS_KEY = "_flutter_vfs_";

function vfsLoad(): Record<string, { content: string; lastModified: number; size: number; type: string }> {
  try {
    return JSON.parse(localStorage.getItem(VFS_KEY) ?? "{}");
  } catch {
    return {};
  }
}

function vfsSave(vfs: Record<string, unknown>): void {
  localStorage.setItem(VFS_KEY, JSON.stringify(vfs));
}

// ─── PathProvider ─────────────────────────────────────────────────────────────
export class PathProvider {
  /** Application documents directory (persistent storage) */
  static async getApplicationDocumentsDirectory(): Promise<Directory> {
    return PathProvider._makeDir("/documents");
  }

  /** Temporary directory (cache) */
  static async getTemporaryDirectory(): Promise<Directory> {
    return PathProvider._makeDir("/temp");
  }

  /** Application support directory */
  static async getApplicationSupportDirectory(): Promise<Directory> {
    return PathProvider._makeDir("/support");
  }

  /** Downloads directory */
  static async getDownloadsDirectory(): Promise<Directory | null> {
    return PathProvider._makeDir("/downloads");
  }

  /** Application cache directory */
  static async getApplicationCacheDirectory(): Promise<Directory> {
    return PathProvider._makeDir("/cache");
  }

  /** External storage (N/A on web — returns documents) */
  static async getExternalStorageDirectory(): Promise<Directory | null> {
    return PathProvider._makeDir("/external");
  }

  private static _makeDir(path: string): Directory {
    return {
      path,
      exists: () => true,
      create: async ({ recursive = false } = {}) => PathProvider._makeDir(path),
      list: async () => {
        const vfs = vfsLoad();
        return Object.entries(vfs)
          .filter(([k]) => k.startsWith(path + "/"))
          .map(([k, v]) => ({
            name: k.slice(path.length + 1),
            path: k,
            size: v.size,
            type: v.type,
            lastModified: v.lastModified,
          }));
      },
      delete: async ({ recursive = false } = {}) => {
        const vfs = vfsLoad();
        Object.keys(vfs)
          .filter((k) => recursive ? k.startsWith(path) : k === path)
          .forEach((k) => delete vfs[k]);
        vfsSave(vfs);
      },
    };
  }
}

// ─── File operations ──────────────────────────────────────────────────────────
export const File = {
  async write(path: string, content: string, type = "text/plain"): Promise<void> {
    const vfs = vfsLoad();
    vfs[path] = { content, lastModified: Date.now(), size: content.length, type };
    vfsSave(vfs);
  },

  async read(path: string): Promise<string | null> {
    const vfs = vfsLoad();
    return vfs[path]?.content ?? null;
  },

  async exists(path: string): Promise<boolean> {
    const vfs = vfsLoad();
    return path in vfs;
  },

  async delete(path: string): Promise<void> {
    const vfs = vfsLoad();
    delete vfs[path];
    vfsSave(vfs);
  },

  async rename(oldPath: string, newPath: string): Promise<void> {
    const vfs = vfsLoad();
    if (vfs[oldPath]) {
      vfs[newPath] = vfs[oldPath];
      delete vfs[oldPath];
      vfsSave(vfs);
    }
  },

  /** Download file to user's actual downloads */
  async downloadToDevice(path: string, filename: string): Promise<void> {
    const vfs = vfsLoad();
    const entry = vfs[path];
    if (!entry) throw new Error(`File not found: ${path}`);
    const blob = new Blob([entry.content], { type: entry.type });
    const url = URL.createObjectURL(blob);
    const a = document.createElement("a");
    a.href = url;
    a.download = filename;
    a.click();
    URL.revokeObjectURL(url);
  },
};

// ─── join path helper ─────────────────────────────────────────────────────────
export function join(...parts: string[]): string {
  return parts.join("/").replace(/\/+/g, "/");
}

export function basename(path: string): string {
  return path.split("/").filter(Boolean).pop() ?? path;
}

export function dirname(path: string): string {
  const parts = path.split("/").filter(Boolean);
  parts.pop();
  return "/" + parts.join("/");
}

export function extension(path: string): string {
  const name = basename(path);
  const dot = name.lastIndexOf(".");
  return dot >= 0 ? name.slice(dot) : "";
}

/**
 * shared-preferences.ts — Flutter `shared_preferences` package equivalent for React
 * Mirrors: SharedPreferences, getBool, getInt, getDouble, getString, getStringList, setBool, etc.
 * Uses localStorage as the underlying store.
 */

const PREFIX = "sp_";

export class SharedPreferences {
  private static _instance: SharedPreferences | null = null;

  private constructor() {}

  /** Get the singleton SharedPreferences instance */
  static getInstance(): SharedPreferences {
    if (!this._instance) {
      this._instance = new SharedPreferences();
    }
    return this._instance;
  }

  // ─── Getters ─────────────────────────────────────────────────────────────
  getBool(key: string): boolean | null {
    const v = localStorage.getItem(PREFIX + key);
    if (v === null) return null;
    return v === "true";
  }

  getInt(key: string): number | null {
    const v = localStorage.getItem(PREFIX + key);
    if (v === null) return null;
    const n = parseInt(v, 10);
    return isNaN(n) ? null : n;
  }

  getDouble(key: string): number | null {
    const v = localStorage.getItem(PREFIX + key);
    if (v === null) return null;
    const n = parseFloat(v);
    return isNaN(n) ? null : n;
  }

  getString(key: string): string | null {
    return localStorage.getItem(PREFIX + key);
  }

  getStringList(key: string): string[] | null {
    const v = localStorage.getItem(PREFIX + key);
    if (v === null) return null;
    try {
      return JSON.parse(v) as string[];
    } catch {
      return null;
    }
  }

  // ─── Setters ─────────────────────────────────────────────────────────────
  async setBool(key: string, value: boolean): Promise<boolean> {
    localStorage.setItem(PREFIX + key, String(value));
    return true;
  }

  async setInt(key: string, value: number): Promise<boolean> {
    localStorage.setItem(PREFIX + key, String(Math.trunc(value)));
    return true;
  }

  async setDouble(key: string, value: number): Promise<boolean> {
    localStorage.setItem(PREFIX + key, String(value));
    return true;
  }

  async setString(key: string, value: string): Promise<boolean> {
    localStorage.setItem(PREFIX + key, value);
    return true;
  }

  async setStringList(key: string, value: string[]): Promise<boolean> {
    localStorage.setItem(PREFIX + key, JSON.stringify(value));
    return true;
  }

  // ─── Management ──────────────────────────────────────────────────────────
  async remove(key: string): Promise<boolean> {
    localStorage.removeItem(PREFIX + key);
    return true;
  }

  async clear(): Promise<bool> {
    const keysToRemove = Object.keys(localStorage).filter((k) => k.startsWith(PREFIX));
    keysToRemove.forEach((k) => localStorage.removeItem(k));
    return true;
  }

  containsKey(key: string): boolean {
    return localStorage.getItem(PREFIX + key) !== null;
  }

  getKeys(): Set<string> {
    return new Set(
      Object.keys(localStorage)
        .filter((k) => k.startsWith(PREFIX))
        .map((k) => k.slice(PREFIX.length))
    );
  }

  // ─── Static factory ───────────────────────────────────────────────────────
  static async getInstance_async(): Promise<SharedPreferences> {
    return SharedPreferences.getInstance();
  }
}

// ─── useSharedPreferences hook ────────────────────────────────────────────────
import { useState } from "react";

export function useSharedPreference<T>(
  key: string,
  defaultValue: T
): [T, (value: T) => void] {
  const prefs = SharedPreferences.getInstance();

  const read = (): T => {
    if (typeof defaultValue === "boolean") return (prefs.getBool(key) ?? defaultValue) as T;
    if (typeof defaultValue === "number") {
      if (Number.isInteger(defaultValue)) return (prefs.getInt(key) ?? defaultValue) as T;
      return (prefs.getDouble(key) ?? defaultValue) as T;
    }
    if (Array.isArray(defaultValue)) return (prefs.getStringList(key) ?? defaultValue) as T;
    return (prefs.getString(key) ?? defaultValue) as T;
  };

  const [value, setValue] = useState<T>(read);

  const save = (v: T) => {
    setValue(v);
    if (typeof v === "boolean") prefs.setBool(key, v as boolean);
    else if (typeof v === "number") {
      if (Number.isInteger(v)) prefs.setInt(key, v as number);
      else prefs.setDouble(key, v as number);
    } else if (Array.isArray(v)) prefs.setStringList(key, v as string[]);
    else prefs.setString(key, String(v));
  };

  return [value, save];
}

// Fix TypeScript bool type
type bool = boolean;

/**
 * url-launcher.ts — Flutter `url_launcher` package equivalent for React
 * Mirrors: launchUrl, canLaunchUrl, closeInAppWebView, LaunchMode
 */

// ─── LaunchMode ───────────────────────────────────────────────────────────────
export enum LaunchMode {
  platformDefault = "platformDefault",
  inAppBrowserView = "inAppBrowserView",
  externalApplication = "externalApplication",
  externalNonBrowserApplication = "externalNonBrowserApplication",
}

// ─── launchUrl ────────────────────────────────────────────────────────────────
export interface LaunchUrlOptions {
  mode?: LaunchMode;
  webViewConfiguration?: { enableJavaScript?: boolean; enableDomStorage?: boolean };
  webOnlyWindowName?: string;
}

export async function launchUrl(url: string, options: LaunchUrlOptions = {}): Promise<boolean> {
  try {
    const { mode = LaunchMode.platformDefault, webOnlyWindowName = "_blank" } = options;

    if (mode === LaunchMode.inAppBrowserView) {
      window.open(url, "_self");
    } else {
      window.open(url, webOnlyWindowName, "noopener,noreferrer");
    }
    return true;
  } catch {
    return false;
  }
}

// ─── canLaunchUrl ─────────────────────────────────────────────────────────────
export async function canLaunchUrl(url: string): Promise<boolean> {
  try {
    const u = new URL(url);
    return ["http:", "https:", "mailto:", "tel:", "sms:"].includes(u.protocol);
  } catch {
    return false;
  }
}

// ─── Scheme helpers ───────────────────────────────────────────────────────────
export function mailtoUri(
  address: string,
  options: {
    subject?: string;
    body?: string;
    cc?: string;
    bcc?: string;
  } = {}
): string {
  const params = new URLSearchParams();
  if (options.subject) params.append("subject", options.subject);
  if (options.body) params.append("body", options.body);
  if (options.cc) params.append("cc", options.cc);
  if (options.bcc) params.append("bcc", options.bcc);
  const query = params.toString();
  return `mailto:${address}${query ? "?" + query : ""}`;
}

export function telUri(phoneNumber: string): string {
  return `tel:${phoneNumber.replace(/\s/g, "")}`;
}

export function smsUri(phoneNumber: string, body?: string): string {
  return `sms:${phoneNumber}${body ? `?body=${encodeURIComponent(body)}` : ""}`;
}

export async function launchEmail(
  address: string,
  options: { subject?: string; body?: string } = {}
): Promise<boolean> {
  return launchUrl(mailtoUri(address, options));
}

export async function launchPhone(phoneNumber: string): Promise<boolean> {
  return launchUrl(telUri(phoneNumber));
}

export async function launchSms(phoneNumber: string, body?: string): Promise<boolean> {
  return launchUrl(smsUri(phoneNumber, body));
}

// ─── closeInAppWebView ────────────────────────────────────────────────────────
export function closeInAppWebView(): void {
  window.close();
}

/**
 * validators.ts — Flutter form validators equivalent for React
 * Mirrors: Flutter's validator pattern (returns null if valid, string if invalid)
 */

export type ValidatorFn<T = string> = (value: T) => string | null;

// ─── Basic validators ─────────────────────────────────────────────────────────
export function required(message = "This field is required"): ValidatorFn {
  return (value: string) => {
    if (!value || value.trim() === "") return message;
    return null;
  };
}

export function minLength(min: number, message?: string): ValidatorFn {
  return (value: string) => {
    if (value.length < min) return message ?? `Must be at least ${min} characters`;
    return null;
  };
}

export function maxLength(max: number, message?: string): ValidatorFn {
  return (value: string) => {
    if (value.length > max) return message ?? `Must be at most ${max} characters`;
    return null;
  };
}

export function exactLength(length: number, message?: string): ValidatorFn {
  return (value: string) => {
    if (value.length !== length) return message ?? `Must be exactly ${length} characters`;
    return null;
  };
}

// ─── Format validators ────────────────────────────────────────────────────────
export function emailValidator(message = "Enter a valid email address"): ValidatorFn {
  return (value: string) => {
    const re = /^[^\s@]+@[^\s@]+\.[^\s@]+$/;
    if (!re.test(value)) return message;
    return null;
  };
}

export function phoneValidator(message = "Enter a valid phone number"): ValidatorFn {
  return (value: string) => {
    const cleaned = value.replace(/[\s\-().+]/g, "");
    if (!/^\d{7,15}$/.test(cleaned)) return message;
    return null;
  };
}

export function urlValidator(message = "Enter a valid URL"): ValidatorFn {
  return (value: string) => {
    try {
      const u = new URL(value);
      if (!["http:", "https:"].includes(u.protocol)) return message;
      return null;
    } catch {
      return message;
    }
  };
}

export function numericValidator(message = "Must be a number"): ValidatorFn {
  return (value: string) => {
    if (isNaN(Number(value)) || value.trim() === "") return message;
    return null;
  };
}

export function integerValidator(message = "Must be an integer"): ValidatorFn {
  return (value: string) => {
    if (!/^-?\d+$/.test(value.trim())) return message;
    return null;
  };
}

// ─── Range validators ─────────────────────────────────────────────────────────
export function min(minVal: number, message?: string): ValidatorFn {
  return (value: string) => {
    const n = Number(value);
    if (isNaN(n) || n < minVal) return message ?? `Must be at least ${minVal}`;
    return null;
  };
}

export function max(maxVal: number, message?: string): ValidatorFn {
  return (value: string) => {
    const n = Number(value);
    if (isNaN(n) || n > maxVal) return message ?? `Must be at most ${maxVal}`;
    return null;
  };
}

export function range(minVal: number, maxVal: number, message?: string): ValidatorFn {
  return (value: string) => {
    const n = Number(value);
    if (isNaN(n) || n < minVal || n > maxVal)
      return message ?? `Must be between ${minVal} and ${maxVal}`;
    return null;
  };
}

// ─── Pattern validators ───────────────────────────────────────────────────────
export function pattern(regex: RegExp, message = "Invalid format"): ValidatorFn {
  return (value: string) => {
    if (!regex.test(value)) return message;
    return null;
  };
}

export function alphaOnly(message = "Only letters are allowed"): ValidatorFn {
  return pattern(/^[a-zA-Z]+$/, message);
}

export function alphanumeric(message = "Only letters and numbers are allowed"): ValidatorFn {
  return pattern(/^[a-zA-Z0-9]+$/, message);
}

export function noWhitespace(message = "Spaces are not allowed"): ValidatorFn {
  return (value: string) => {
    if (/\s/.test(value)) return message;
    return null;
  };
}

// ─── Password validators ──────────────────────────────────────────────────────
export function passwordStrength(
  options: {
    minLength?: number;
    requireUppercase?: boolean;
    requireLowercase?: boolean;
    requireNumbers?: boolean;
    requireSpecial?: boolean;
  } = {}
): ValidatorFn {
  const {
    minLength: ml = 8,
    requireUppercase = true,
    requireLowercase = true,
    requireNumbers = true,
    requireSpecial = false,
  } = options;

  return (value: string) => {
    if (value.length < ml) return `Password must be at least ${ml} characters`;
    if (requireUppercase && !/[A-Z]/.test(value)) return "Password must contain an uppercase letter";
    if (requireLowercase && !/[a-z]/.test(value)) return "Password must contain a lowercase letter";
    if (requireNumbers && !/[0-9]/.test(value)) return "Password must contain a number";
    if (requireSpecial && !/[^a-zA-Z0-9]/.test(value)) return "Password must contain a special character";
    return null;
  };
}

export function mustMatch(matchValue: string, message = "Values do not match"): ValidatorFn {
  return (value: string) => {
    if (value !== matchValue) return message;
    return null;
  };
}

// ─── Compose validators ───────────────────────────────────────────────────────
/** Run validators in sequence, return first error found */
export function compose<T = string>(...validators: ValidatorFn<T>[]): ValidatorFn<T> {
  return (value: T) => {
    for (const v of validators) {
      const err = v(value);
      if (err !== null) return err;
    }
    return null;
  };
}

/** Run all validators and collect all errors */
export function composeAll<T = string>(...validators: ValidatorFn<T>[]): (value: T) => string[] {
  return (value: T) => validators.map((v) => v(value)).filter((e) => e !== null) as string[];
}
